<div class="toast" id="toast"></div>
<script>
const API='dispatch_next_api.php';let state={date:localDateString(),search:'',users:[],data:null,me:null,currentDetail:null,mode:'personal',scope:window.innerWidth<760?'mobile':'desktop',mobileView:localStorage.dispatch_next_mobile_view||'card',columns:[],editColumns:null,colorPrefs:{},editColorPrefs:null,saveTimers:{},emptyDeleteTimers:{},dragRow:null,newRows:{},localCellEdits:{},cellSaveStatus:{},detailTab:'detail',detailSaveStatus:{},pendingRender:false,noticeFilter:'pending_all',noticeSearch:'',noticePage:1,noticeCenterData:null,selectedNoticeId:'',noticeRules:{},peopleFilter:{personal:[],dispatch:[]},filters:{personal:{status:[],priority:[],overdue:false,collapsed:false},dispatch:{status:[],priority:[],overdue:false,collapsed:false}},lastSilentSync:0,lastVersionCheck:0,lastNoticeSync:0,lastOnlineSync:0,syncVersion:'',versionCheckRunning:false,ticker:null,resizeObserver:null,layoutWatcher:null,layoutSignature:''};
const defaultColumns=[['row_handle','','handle'],['complete','完成','complete'],['priority','优先级','select'],['title','任务标题','text'],['project','项目','textarea'],['due_at','截止日期','datetime'],['assigned_to','负责人','user'],['dispatch_mode','方式','mode'],['creator_name','派工来自','readonly'],['actions','操作','actions']];
function $(s,r=document){return r.querySelector(s)}function $all(s,r=document){return Array.from(r.querySelectorAll(s))}
function esc(v){return String(v??'').replace(/[&<>"']/g,s=>({'&':'&amp;','<':'&lt;','>':'&gt;','"':'&quot;',"'":'&#039;'}[s]))}
function toast(msg){const n=$('#toast');n.textContent=msg;n.classList.add('show');clearTimeout(n.t);n.t=setTimeout(()=>n.classList.remove('show'),1800)}
async function api(action,data={},file){let opt={method:'POST',credentials:'same-origin'};if(file){let fd=new FormData();fd.set('action',action);Object.entries(data).forEach(([k,v])=>fd.set(k,v));fd.set('file',file);opt.body=fd}else{opt.headers={'Content-Type':'application/json'};opt.body=JSON.stringify(Object.assign({action},data))}let r=await fetch(API,opt);let j=await r.json().catch(()=>({ok:false,error:'接口返回异常'}));if(!j.ok)throw new Error(j.error||'操作失败');return j.data}
function localDateString(d=new Date()){let pad=n=>String(n).padStart(2,'0');return d.getFullYear()+'-'+pad(d.getMonth()+1)+'-'+pad(d.getDate())}
function today(){return localDateString()}
function setDark(on){document.body.classList.toggle('dark',on);localStorage.dispatch_next_dark=on?'1':'0';$('#darkBtn').textContent='暗黑：'+(on?'开':'关')}
function setWater(on){document.body.classList.toggle('watermark',on);localStorage.dispatch_next_water=on?'1':'0';$('#waterBtn').textContent='水印：'+(on?'开':'关')}
function setMobileView(view,save=true){state.mobileView=view==='table'?'table':'card';document.body.classList.toggle('mobile-view-table',state.mobileView==='table');localStorage.dispatch_next_mobile_view=state.mobileView;$all('[data-mobile-view-toggle]').forEach(btn=>btn.textContent=state.mobileView==='table'?'卡片':'表格');if(save)checkTableLayout(true)}
function userOptions(selected='',withDept=true){return state.users.map(u=>`<option value="${u.id}" ${String(selected)===String(u.id)?'selected':''}>${esc(withDept?(u.name+' / '+(u.department||'-')):u.name)}</option>`).join('')}
async function init(){setDark(localStorage.dispatch_next_dark==='1');setWater(localStorage.dispatch_next_water==='1');setMobileView(state.mobileView,false);state.date=today();updateStatusClock();$('#workDate').value=state.date;state.users=await api('list_users');state.me=await api('me');await loadPeopleFilterPrefs();await loadNoticeRules();renderPeopleFilter();await loadTablePrefs();bind();bindStatusMenus();await load({jumpToday:true});bindTableResizeObserver();startLayoutWatcher();startSyncTicker();window.addEventListener('resize',scheduleTableWidthApply,{passive:true});window.visualViewport?.addEventListener('resize',scheduleTableWidthApply,{passive:true});document.addEventListener('visibilitychange',()=>{if(!document.hidden)resumeSync()});window.addEventListener('focus',resumeSync);window.addEventListener('pageshow',resumeSync);window.addEventListener('pagehide',sendDispatchOnlineLeave);window.addEventListener('beforeunload',sendDispatchOnlineLeave)}
function renderPeopleFilter(type){let types=type?[type]:['personal','dispatch'];types.forEach(t=>{let panel=document.querySelector(`[data-filter-panel="${t}"]`);if(!panel)return;let selected=state.peopleFilter[t]||[];panel.innerHTML=state.users.map(u=>`<button class="personChip ${selected.includes(String(u.id))?'active':''}" type="button" data-filter-person="${u.id}" data-filter-type="${t}" title="${esc(u.name)} / ${esc(u.department||'-')}">${esc(u.name)}<small>${esc(u.department||'')}</small></button>`).join('')+'<button class="personChip done" type="button" data-filter-done="'+t+'">完成</button><button class="personChip" type="button" data-filter-clear="'+t+'">全部</button>';updatePeopleFilterLabel(t)})}
function updatePeopleFilterLabel(type){let btn=document.querySelector(`[data-filter-button="${type}"]`);if(!btn)return;let selected=state.peopleFilter[type]||[];if(!selected.length){btn.textContent='人员：全部';return}let names=state.users.filter(u=>selected.includes(String(u.id))).map(u=>u.name);btn.textContent=names.length>2?'人员：'+names.slice(0,2).join('、')+' +'+(names.length-2):'人员：'+names.join('、')}
function normalizePeopleFilterPrefs(value){let ids=new Set(state.users.map(u=>String(u.id))),src=value&&typeof value==='object'?value:{},clean={personal:[],dispatch:[]};['personal','dispatch'].forEach(type=>{clean[type]=(Array.isArray(src[type])?src[type]:[]).map(String).filter(id=>ids.has(id))});return clean}
async function loadPeopleFilterPrefs(){try{let r=await api('get_user_pref',{key:'dispatch_next_people_filter'});state.peopleFilter=normalizePeopleFilterPrefs(r.value)}catch(e){state.peopleFilter=normalizePeopleFilterPrefs(state.peopleFilter)}}
function savePeopleFilterPrefs(){let value=normalizePeopleFilterPrefs(state.peopleFilter);state.peopleFilter=value;api('save_user_pref',{key:'dispatch_next_people_filter',value}).catch(e=>toast('人员筛选保存失败：'+e.message))}
function defaultNoticeRules(){return {default_filter:'pending_all',hide_read:0,top_unread_only:1,auto_read_on_open:1,compact_limit:5,mute_done:0}}
function normalizeNoticeRules(value){let d=defaultNoticeRules(),src=value&&typeof value==='object'?value:{};let next=Object.assign({},d,src),allowed=['pending_all','new_dispatch','due_today','overdue','confirm','urge','blocked','history','activity'];next.default_filter=allowed.includes(next.default_filter)?next.default_filter:d.default_filter;next.hide_read=Number(next.hide_read)?1:0;next.top_unread_only=Number(next.top_unread_only)?1:0;next.auto_read_on_open=Number(next.auto_read_on_open)?1:0;next.mute_done=Number(next.mute_done)?1:0;next.compact_limit=Math.max(3,Math.min(10,Number(next.compact_limit)||5));return next}
async function loadNoticeRules(){try{let r=await api('get_user_pref',{key:'dispatch_next_notice_rules'});state.noticeRules=normalizeNoticeRules(r.value)}catch(e){state.noticeRules=defaultNoticeRules()}state.noticeFilter=state.noticeRules.default_filter||'pending_all'}
function saveNoticeRules(){state.noticeRules=normalizeNoticeRules(state.noticeRules);api('save_user_pref',{key:'dispatch_next_notice_rules',value:state.noticeRules}).catch(e=>toast('通知规则保存失败：'+e.message))}
function renderStatusFilter(type){let panel=document.querySelector(`[data-status-panel="${type}"]`);if(!panel)return;let f=state.filters[type];let statuses=[['pending_accept','待接收'],['in_progress','进行中'],['paused','暂停'],['submitted','待确认'],['done','已完成'],['cancelled','已取消']];panel.innerHTML=statuses.map(s=>`<button class="personChip ${f.status.includes(s[0])?'active':''}" type="button" data-filter-kind="status" data-filter-type="${type}" data-filter-value="${s[0]}">${s[1]}</button>`).join('')+'<button class="personChip" type="button" data-status-clear="'+type+'">全部状态</button>';updateStatusFilterLabel(type)}
function updateStatusFilterLabel(type){let btn=document.querySelector(`[data-status-button="${type}"]`);if(!btn)return;let selected=state.filters[type]?.status||[];if(!selected.length){btn.textContent='状态：全部';return}let map={pending_accept:'待接收',in_progress:'进行中',paused:'暂停',submitted:'待确认',done:'已完成',cancelled:'已取消'};let names=selected.map(v=>map[v]||v);btn.textContent=names.length>2?'状态：'+names.slice(0,2).join('、')+' +'+(names.length-2):'状态：'+names.join('、')}
function defaultColorPrefs(){return {assignee:'#111827',creator:'#047857',method:'#3730a3',mention_naming:'#2563eb',mention_bom:'#8b3a1e',mention_quote:'#047857',mention_plm:'#6d28d9',mention_snapshot:'#0f766e',mention_material:'#7c3aed',mention_dispatch:'#1f2937',mention_opportunity:'#b45309',overdue_bg:'#fff7ed',overdue_line:'#facc15',done_bg:'#fafafa',icon_style:'minimal',ref_chip_mode:'standard'}}
function applyColorPrefs(){let p=Object.assign(defaultColorPrefs(),state.colorPrefs||{}),root=document.documentElement;root.style.setProperty('--dispatch-color-assignee',p.assignee);root.style.setProperty('--dispatch-color-creator',p.creator);root.style.setProperty('--dispatch-color-method',p.method);root.style.setProperty('--dispatch-color-mention-naming',p.mention_naming);root.style.setProperty('--dispatch-color-mention-bom',p.mention_bom);root.style.setProperty('--dispatch-color-mention-quote',p.mention_quote);root.style.setProperty('--dispatch-color-mention-plm',p.mention_plm);root.style.setProperty('--dispatch-color-mention-snapshot',p.mention_snapshot);root.style.setProperty('--ref-naming-text',p.mention_naming);root.style.setProperty('--ref-bom-text',p.mention_bom);root.style.setProperty('--ref-quote-text',p.mention_quote);root.style.setProperty('--ref-plm-text',p.mention_plm);root.style.setProperty('--ref-snapshot-text',p.mention_snapshot);root.style.setProperty('--ref-material-text',p.mention_material);root.style.setProperty('--ref-dispatch-text',p.mention_dispatch);root.style.setProperty('--ref-opportunity-text',p.mention_opportunity);root.style.setProperty('--dispatch-overdue-bg',p.overdue_bg);root.style.setProperty('--dispatch-overdue-line',p.overdue_line);root.style.setProperty('--dispatch-done-bg',p.done_bg);document.body.classList.toggle('ref-chip-mode-minimal',p.ref_chip_mode==='minimal');document.body.classList.toggle('ref-chip-mode-emphasis',p.ref_chip_mode==='emphasis')}
function actionIconClass(){return 'iconStyle-'+esc((state.colorPrefs||{}).icon_style||'minimal')}
function actionIcon(type){let style=(state.colorPrefs||{}).icon_style||'minimal';let sets={minimal:{detail:'⊙',urge:'!',delete:'×'},compact:{detail:'◎',urge:'‼',delete:'×'},soft:{detail:'◉',urge:'⚑',delete:'✕'},outline:{detail:'⌕',urge:'↯',delete:'⌫'},solid:{detail:'◆',urge:'▲',delete:'✕'},symbol:{detail:'◌',urge:'⚑',delete:'⌧'},square:{detail:'□',urge:'△',delete:'⌧'},line:{detail:'⌕',urge:'!',delete:'×'}};return esc((sets[style]||sets.minimal)[type]||type)}
async function loadTablePrefs(){try{let p=await api('get_table_prefs',{scope:state.scope});state.columns=(p.columns||[]).sort((a,b)=>(Number(a.order)||0)-(Number(b.order)||0));state.colorPrefs=Object.assign(defaultColorPrefs(),p.color_prefs||{});if(!state.columns.some(c=>c.key==='row_handle'))state.columns.unshift({key:'row_handle',label:'',type:'handle',visible:1,width:34,minWidth:28,maxWidth:56,order:5})}catch(e){state.columns=defaultColumns.map((c,i)=>({key:c[0],label:c[1],type:c[2],visible:1,width:defaultColWidth(c[0]),minWidth:28,maxWidth:720,order:(i+1)*10}));state.colorPrefs=defaultColorPrefs()}applyColorPrefs()}
function bind(){document.body.addEventListener('click',async e=>{let viewToggle=e.target.closest('[data-mobile-view-toggle]');if(viewToggle){setMobileView(state.mobileView==='table'?'card':'table');return}let b=e.target.closest('[data-open]');if(b)openForm(b.dataset.open);let d=e.target.closest('[data-day]');if(d){let x=new Date($('#workDate').value);x.setDate(x.getDate()+Number(d.dataset.day));state.date=localDateString(x);$('#workDate').value=state.date;load()}let cmd=e.target.closest('[data-style-cmd]');if(cmd){applyTextStyle(cmd.dataset.styleCmd);return}let color=e.target.closest('[data-style-color]');if(color){applyTextColor(color.dataset.styleColor);return}if(e.target.closest('[data-style-clear]')){applyTextStyle('removeFormat');return}let toggle=e.target.closest('[data-filter-button]');if(toggle){toggleFilterPanel(toggle.dataset.filterButton);return}let statusToggle=e.target.closest('[data-status-button]');if(statusToggle){toggleFilterPanel('status_'+statusToggle.dataset.statusButton);return}let chip=e.target.closest('[data-filter-kind]');if(chip){toggleTableFilter(chip.dataset.filterType,chip.dataset.filterKind,chip.dataset.filterValue);return}let statusClear=e.target.closest('[data-status-clear]');if(statusClear){state.filters[statusClear.dataset.statusClear].status=[];renderStatusFilter(statusClear.dataset.statusClear);renderRowsOnly();return}let clearAll=e.target.closest('[data-filter-clear-all]');if(clearAll){clearTableFilters(clearAll.dataset.filterClearAll);return}let person=e.target.closest('[data-filter-person]');if(person){togglePersonFilter(person.dataset.filterType,person.dataset.filterPerson);return}let clear=e.target.closest('[data-filter-clear]');if(clear){clearPersonFilter(clear.dataset.filterClear);return}let doneFilter=e.target.closest('[data-filter-done]');if(doneFilter){closeFilterPanel(doneFilter.dataset.filterDone);return}if(!e.target.closest('.peopleFilter'))closeAllFilterPanels();if(e.target.closest('[data-notice-check]'))return;let notice=e.target.closest('[data-notice-id]');if(notice){await openNoticeDetail(notice);return}let row=e.target.closest('[data-detail]');if(row)openDetail(row.dataset.detail);let urge=e.target.closest('[data-urge]');if(urge)doUrge(urge.dataset.urge);let del=e.target.closest('[data-del]');if(del)doDelete(del.dataset.del,del.dataset.group);let done=e.target.closest('[data-done]');if(done)quickDone(done.dataset.done,done.dataset.doneStatus);});$('#workDate').onchange=()=>{state.date=$('#workDate').value;load()};$('#taskSearch').oninput=()=>{clearTimeout(state.saveTimers.search);state.saveTimers.search=setTimeout(()=>{state.search=$('#taskSearch').value.trim();load()},300)};$('#todayBtn').onclick=()=>{state.date=today();$('#workDate').value=state.date;load({jumpToday:true})};$('#refreshBtn').onclick=load;$('#darkBtn').onclick=()=>setDark(!document.body.classList.contains('dark'));$('#waterBtn').onclick=()=>setWater(!document.body.classList.contains('watermark'));$('#notifyBtn').onclick=e=>{e.stopPropagation();$('#noticePanel').classList.toggle('show');loadNotifications(false)};document.addEventListener('click',e=>{if(!e.target.closest('#notifyBtn')&&!e.target.closest('#noticePanel'))$('#noticePanel')?.classList.remove('show');if(!e.target.closest('.ref-chip-list'))document.querySelectorAll('.ref-chip-popover:not([hidden])').forEach(p=>p.hidden=true)});$('#toggleDone').onclick=()=>{$('#doneSec').classList.toggle('collapsed');$('#toggleDone').textContent=$('#doneSec').classList.contains('collapsed')?'展开':'折叠'};document.addEventListener('paste',pasteImage)}
function activeEditCell(){let a=document.activeElement;return a&&a.matches&&a.matches('.cell-edit[contenteditable="true"]')?a:null}
function applyTextStyle(cmd){let el=activeEditCell();if(!el)return toast('先点击标题或项目单元格');document.execCommand(cmd,false,null);debounceSaveCell(el.dataset.cellTask,el.dataset.cellField,el.textContent)}
function applyTextColor(color){let el=activeEditCell();if(!el)return toast('先点击标题或项目单元格');document.execCommand('foreColor',false,color);debounceSaveCell(el.dataset.cellTask,el.dataset.cellField,el.textContent)}
function toggleTableFilter(type,kind,value){let f=state.filters[type];if(kind==='overdue'){f.overdue=!f.overdue}else{let arr=f[kind]||[];f[kind]=arr.includes(value)?arr.filter(v=>v!==value):arr.concat([value])}if(kind==='status'){renderStatusFilter(type);renderRowsOnly()}else renderAll()}
function clearTableFilters(type){state.filters[type]={status:[],priority:[],overdue:false,collapsed:false};state.peopleFilter[type]=[];savePeopleFilterPrefs();renderAll();load()}
function toggleFilterPanel(type){let panel=document.querySelector(`[data-filter-panel="${type}"]`);if(!panel)return;document.querySelectorAll('.peopleFilterPanel.show').forEach(p=>{if(p!==panel)p.classList.remove('show')});panel.classList.toggle('show')}
function closeFilterPanel(type){document.querySelector(`[data-filter-panel="${type}"]`)?.classList.remove('show')}
function closeAllFilterPanels(){document.querySelectorAll('.peopleFilterPanel.show').forEach(p=>p.classList.remove('show'))}
function togglePersonFilter(type,id){let s=String(id);let list=state.peopleFilter[type]||[];state.peopleFilter[type]=list.includes(s)?list.filter(v=>v!==s):list.concat([s]);savePeopleFilterPrefs();renderPeopleFilter(type);closeFilterPanel(type);load()}
function clearPersonFilter(type){state.peopleFilter[type]=[];savePeopleFilterPrefs();renderPeopleFilter(type);closeFilterPanel(type);load()}
function updateStatusClock(){let d=new Date();let pad=n=>String(n).padStart(2,'0');let clock=$('[data-status-clock]'),date=$('[data-status-date]');if(clock)clock.textContent=pad(d.getHours())+':'+pad(d.getMinutes())+':'+pad(d.getSeconds());if(date)date.textContent=d.getFullYear()+'-'+pad(d.getMonth()+1)+'-'+pad(d.getDate());renderWorldTimes()}
function worldTimeZones(){return [['本地/北京','Asia/Shanghai','GMT+8'],['纽约','America/New_York','US Eastern'],['伦敦','Europe/London','London'],['柏林','Europe/Berlin','Berlin'],['新加坡','Asia/Singapore','GMT+8']]}
function zoneTime(zone){try{return new Intl.DateTimeFormat('zh-CN',{timeZone:zone,hour:'2-digit',minute:'2-digit',second:'2-digit',hour12:false,month:'2-digit',day:'2-digit'}).format(new Date())}catch(e){return '--:--'}}
function renderWorldTimes(){let box=$('#worldTimeMenu');if(!box)return;box.innerHTML=worldTimeZones().map(z=>`<div class="worldRow"><b>${esc(z[0])}</b><strong>${esc(zoneTime(z[1]))}</strong><span>${esc(z[2])}</span><span>${esc(z[1])}</span></div>`).join('')}
function bindStatusMenus(){document.addEventListener('click',e=>{let btn=e.target.closest('[data-status-menu-toggle]');if(btn){let key=btn.getAttribute('data-status-menu-toggle');let menu=document.querySelector('[data-status-menu="'+key+'"]');document.querySelectorAll('.status-menu.show').forEach(m=>{if(m!==menu)m.classList.remove('show')});if(menu)menu.classList.toggle('show');e.stopPropagation();return}if(!e.target.closest('.status-dropdown'))document.querySelectorAll('.status-menu.show').forEach(m=>m.classList.remove('show'))});document.addEventListener('keydown',e=>{if(e.key==='Escape'){document.querySelectorAll('.status-menu.show').forEach(m=>m.classList.remove('show'));$('#noticePanel')?.classList.remove('show')}})}
async function load(opts={}){if(opts&&opts.type)opts={};let silent=!!opts.silent;try{if(!silent)$('#syncState').textContent='同步中';let fresh=await api('list',{date:state.date,q:state.search,personal_people_ids:state.peopleFilter.personal,dispatch_people_ids:state.peopleFilter.dispatch});mergeLocalCellEdits(fresh);state.data=fresh;state.me=fresh.me;if(fresh.version)state.syncVersion=String(fresh.version);if(!silent||!isTableEditing()){if(silent&&!opts.jumpToday)renderAllPreserveScroll();else renderAll();state.pendingRender=false;$('#syncState').textContent=(silent?'后台已更新 ':'已同步 ')+new Date().toLocaleTimeString('zh-CN',{hour12:false});if(opts.jumpToday)scrollToTodayTasks()}else{state.pendingRender=true;renderMetaOnly();$('#syncState').textContent='正在编辑，后台更新已暂存'}if(!silent)await dailyAcceptNotice()}catch(e){if(!silent){toast(e.message);$('#syncState').textContent='同步失败'}}}
function scrollToTodayTasks(){if(state.date!==today())return;requestAnimationFrame(()=>setTimeout(()=>{let target=document.querySelector('[data-today-task]')||document.querySelector('[data-table-section="dispatch"]')||document.querySelector('[data-table-section="personal"]');if(!target)return;target.scrollIntoView({behavior:'smooth',block:'start'});let wrap=target.closest?.('.tableWrap')||target.querySelector?.('.tableWrap');if(wrap)wrap.scrollLeft=0},80))}
function startSyncTicker(){if(state.ticker)return;try{let blob=new Blob(['setInterval(function(){postMessage(Date.now())},1000)'],{type:'text/javascript'}),url=URL.createObjectURL(blob);state.ticker=new Worker(url);state.ticker.onmessage=backgroundTick}catch(e){setInterval(backgroundTick,1000)}backgroundTick()}
function backgroundTick(){updateStatusClock();if(document.hidden)return;let now=Date.now();if(now-state.lastVersionCheck>2000){state.lastVersionCheck=now;checkSyncVersion()}if(now-state.lastSilentSync>30000){state.lastSilentSync=now;load({silent:true})}if(now-state.lastNoticeSync>60000){state.lastNoticeSync=now;loadNotifications()}if(now-state.lastOnlineSync>30000){state.lastOnlineSync=now;loadOnlineStatus()}}
