function noticeTone(n){let e=String(n.event_type||n.type||'');if(e==='overdue'||e==='task_blocked')return 'red';if(e==='due_today')return 'orange';if(e==='completed_pending_confirm')return 'purple';if(e==='urge')return 'navy';if(e==='task_done'||String(n.status||'')==='handled')return 'green';if(['task_updated','progress_added','attachment_added','system'].includes(e))return 'gray';return 'blue'}
