function isUpdateNotice(n){return String(n.type||'')==='urge'&&String(n.title||'')==='任务已更新'&&n.task_id}
function noticeGroupKey(n){return isUpdateNotice(n)?['update',n.task_id,n.type,n.title,Number(n.is_read||0)?'read':'unread'].join('_'):String(n.id||'')}
function mergeDisplayNotices(rows=[]){let map=new Map(),out=[];for(const n of rows){let key=noticeGroupKey(n);if(!map.has(key)){let copy=Object.assign({},n,{_merged_count:1,_merged_items:[n]});map.set(key,copy);out.push(copy);continue}let item=map.get(key);item._merged_count++;item._merged_items.push(n);if(Number(n.id||0)>Number(item.id||0)||String(n.created_at||'')>String(item.created_at||'')){Object.assign(item,n,{_merged_count:item._merged_count,_merged_items:item._merged_items})}}return out}
