function noticeById(id){return combinedNotices(state.data?.notifications?.items||[]).find(n=>String(n.id)===String(id))||null}
function displayNoticeById(id){return displayNotices(state.data?.notifications?.items||[]).find(n=>String(n.id)===String(id))||noticeById(id)}
function noticeTaskActionsHtml(n,task){if(!n?.task_id)return '';let code=String(n.action_code||''),status=String(task?.status||n.task_status||''),actions=[];if(code==='accept'||status==='pending_accept')actions.push(['accept','接收任务']);if(code==='confirm_done'||status==='submitted')actions.push(['confirm_done','确认完成'],['return_task','退回']);if(code==='overdue'||code==='due_today'||code==='respond_urge')actions.push(['complete','完成']);let html=actions.map(a=>`<button class="btn mini" type="button" onclick="handleNoticeAction('${esc(n.id)}','${a[0]}')">${a[1]}</button>`).join('');if(noticeIsPending(n))html+=`<button class="btn mini" type="button" onclick="snoozeNotice('${esc(n.id)}',30)">稍后提醒</button>`;return html}
function noticePreviewHtml(n){if(!n)return '<div class="noticeEmptyPreview">选择一条通知查看任务摘要和操作。</div>';let task=n.task_id?taskById(n.task_id):null,tone=noticeTone(n);return `<div class="noticePreview"><div class="noticePreviewHeader"><span class="noticeType tone-${tone}">${esc(noticeTypeLabel(n.event_type||n.type))}</span><span class="noticePreviewStatus ${String(n.status||'')==='handled'?'done':''}">${esc(noticeStatusLabel(n))}</span></div><h4>${esc(n.title||'通知')}</h4><p>${esc(n.message||noticeProjectText(n))}</p><div class="noticePreviewGrid"><b>任务状态</b><span>${esc(statusText(task?.status||n.task_status)||'—')}</span><b>时间</b><span>${esc(n.updated_at||n.created_at||'—')}</span><b>任务</b><span>${esc(task?.title||n.task_title||n.task_id||'—')}</span><b>项目</b><span>${esc(task?.project||n.project||'—')}</span><b>负责人</b><span>${esc(task?.assignee_name||n.assignee_name||'—')}</span><b>截止日期</b><span>${esc(formatDue(task?.due_at||n.due_at)||'—')}</span></div><div class="noticePreviewActions">${n.task_id?`<button class="btn mini primary" type="button" onclick="openNoticeById('${esc(n.id)}','${esc(n.task_id)}')">打开任务</button>`:''}${noticeTaskActionsHtml(n,task)}${noticeIsPending(n)?'':`<button class="btn mini" type="button" onclick="markNoticeReadById('${esc(n.id)}')">标记已读</button>`}</div></div>`}
function noticeRulesHtml(){let r=normalizeNoticeRules(state.noticeRules),opts=[['pending_all','全部待处理'],['new_dispatch','新派工待接收'],['due_today','今日到期'],['overdue','已逾期'],['confirm','待我确认'],['urge','催办我的'],['blocked','异常 / 卡住']];return `<div class="noticeRulePanel"><h4>通知规则设置</h4><div class="noticeRuleGrid"><label class="noticeRuleItem"><input type="checkbox" ${r.hide_read?'checked':''} onchange="setNoticeRule('hide_read',this.checked?1:0)"><span><b>历史默认隐藏已读</b><span>只影响历史记录，不影响待处理事项。</span></span></label><label class="noticeRuleItem"><input type="checkbox" checked disabled><span><b>顶部只显示待处理</b><span>铃铛数字只统计需要动作的通知。</span></span></label><label class="noticeRuleItem"><input type="checkbox" ${r.auto_read_on_open?'checked':''} onchange="setNoticeRule('auto_read_on_open',this.checked?1:0)"><span><b>打开任务自动已读</b><span>只影响阅读状态，不会处理待办动作。</span></span></label><label class="noticeRuleItem"><input type="checkbox" ${r.mute_done?'checked':''} onchange="setNoticeRule('mute_done',this.checked?1:0)"><span><b>弱化完成通知</b><span>完成类通知不进入顶部浮层。</span></span></label><label class="noticeRuleItem"><span><b>默认打开分类</b><span>进入通知中心时优先显示的分类。</span></span><select onchange="setNoticeRule('default_filter',this.value)">${opts.map(o=>`<option value="${o[0]}" ${r.default_filter===o[0]?'selected':''}>${o[1]}</option>`).join('')}</select></label><label class="noticeRuleItem"><span><b>顶部显示条数</b><span>右上角待处理浮层最多显示几条。</span></span><select onchange="setNoticeRule('compact_limit',this.value)">${[3,5,8,10].map(n=>`<option value="${n}" ${r.compact_limit===n?'selected':''}>${n} 条</option>`).join('')}</select></label><div class="noticeRuleItem noticeRuleFull"><span><b>说明</b><span>已读只是看过；已处理必须完成接收、确认、进度、完成等实际动作。</span></span></div></div></div>`}
async function refreshNoticeCenterData(){state.noticeCenterData=await api('notification_center_data',{category:state.noticeFilter,keyword:state.noticeSearch,page:state.noticePage,page_size:20});state.noticePage=Number(state.noticeCenterData?.pagination?.page||state.noticePage||1);if(state.data?.notifications){state.data.notifications.counts=state.noticeCenterData.counts||{};state.data.notifications.pending_count=Number(state.noticeCenterData.pending_count||0);state.data.notifications.unread_count=Number(state.noticeCenterData.pending_count||0);updateDispatchMessageMeta()}}
function renderNoticeCenter(){let data=state.noticeCenterData||{counts:{},list:[],pagination:{page:1,total:0,total_pages:1}},list=data.list||[],counts=data.counts||{},pg=data.pagination||{page:1,total:0,total_pages:1},tabs=[['pending_all','全部待处理'],['new_dispatch','新派工'],['due_today','今日到期'],['overdue','已逾期'],['confirm','待确认'],['urge','催办'],['blocked','异常 / 卡住'],['history','历史记录'],['activity','操作动态']],totalPages=Math.max(1,Number(pg.total_pages||1)),prevDisabled=Number(pg.page||1)<=1?'disabled':'',nextDisabled=Number(pg.page||1)>=totalPages?'disabled':'';if(!tabs.some(t=>t[0]===state.noticeFilter))state.noticeFilter='pending_all';if(!state.selectedNoticeId||!list.some(n=>String(n.id)===String(state.selectedNoticeId)))state.selectedNoticeId=list[0]?String(list[0].id):'';$('#noticeCenterHint').textContent='查看并处理派工提醒。';let pager=`<div class="noticePageControls"><button class="btn mini" type="button" ${prevDisabled} onclick="setNoticePage(${Number(pg.page||1)-1})">上一页</button><b>${Number(pg.page||1)} / ${totalPages}</b><button class="btn mini" type="button" ${nextDisabled} onclick="setNoticePage(${Number(pg.page||1)+1})">下一页</button></div>`;let tabHtml=tabs.map(t=>`<button class="dispatchNoticeTab ${state.noticeFilter===t[0]?'active':''}" type="button" onclick="setNoticeFilter('${t[0]}')"><span>${t[1]}</span><b>${Number(counts[t[0]]||0)}</b></button>`).join('');let selected=list.find(n=>String(n.id)===String(state.selectedNoticeId))||null,emptyText=state.noticeFilter==='pending_all'?'暂无待处理事项':'当前分类没有通知摘要';$('#noticeCenterBody').innerHTML=`<div class="dispatchNoticeCenter"><div class="dispatchNoticeTabs">${tabHtml}</div><div class="noticeSearchRow"><input value="${esc(state.noticeSearch)}" placeholder="搜索标题 / 项目 / 类型 / 时间" oninput="setNoticeSearch(this.value)"><button class="btn mini" type="button" onclick="setNoticeSearch('')">清空</button>${pager}</div><div class="dispatchNoticeWork"><section class="noticeMain"><div class="noticeCenterList">${list.map(n=>noticeRowHtml(n,false)).join('')||`<div class="dispatchNoticeEmpty"><b>${emptyText}</b><span>${state.noticeFilter==='pending_all'?'完成动作后待处理会自动消失。':'重复任务更新已按任务摘要合并。'}</span>${state.noticeFilter==='pending_all'?"<button class=\"btn mini\" type=\"button\" onclick=\"setNoticeFilter('history')\">查看历史记录</button>":''}</div>`}</div><div class="noticePager"><span>第 ${Number(pg.page||1)} / ${totalPages} 页 · 共 ${Number(pg.total||0)} 条</span>${pager}</div></section><aside id="noticePreviewBox">${noticePreviewHtml(selected)}</aside></div></div>`;$('#noticeCenterFoot').textContent='批量已读只处理历史阅读状态，待处理事项必须完成对应动作后才会消失。';let clean=$('#noticeCleanupBtn');if(clean)clean.style.display=state.me?.is_admin?'inline-flex':'none'}
async function setNoticeFilter(filter){state.noticeFilter=filter;state.noticePage=1;state.selectedNoticeId='';await refreshNoticeCenterData();renderNoticeCenter();renderNotices(state.data?.notifications?.items||[])}
function setNoticeSearch(value){state.noticeSearch=String(value||'');state.noticePage=1;state.selectedNoticeId='';clearTimeout(state.saveTimers.noticeSearch);state.saveTimers.noticeSearch=setTimeout(async()=>{await refreshNoticeCenterData();renderNoticeCenter()},180)}
async function setNoticePage(page){state.noticePage=Number(page)||1;state.selectedNoticeId='';await refreshNoticeCenterData();renderNoticeCenter()}
function selectNoticePreview(id){state.selectedNoticeId=String(id||'');renderNoticeCenter()}
async function openNoticeCenter(){if(!['pending_all','new_dispatch','due_today','overdue','confirm','urge','blocked','history','activity'].includes(state.noticeFilter))state.noticeFilter='pending_all';await loadNotifications(false);await refreshNoticeCenterData();renderNoticeCenter();$('#noticePanel')?.classList.remove('show');$('#noticeCenterModal').showModal()}
async function setNoticeRule(key,value){state.noticeRules=normalizeNoticeRules(Object.assign({},state.noticeRules,{[key]:value}));saveNoticeRules();if(key==='default_filter')state.noticeFilter=state.noticeRules.default_filter;await refreshNoticeCenterData();renderNoticeCenter();renderNotices(state.data?.notifications?.items||[]);toast('通知规则已保存')}
async function openNoticeById(id,taskId){if(normalizeNoticeRules(state.noticeRules).auto_read_on_open)await markNoticeReadById(id,false);if(taskId)openDetail(taskId);else loadNotifications(false)}
async function refreshNoticeCenterIfOpen(){if($('#noticeCenterModal')?.open){await refreshNoticeCenterData();renderNoticeCenter()}}
async function noticeTaskAction(action,taskId,noticeId){if(!taskId)return;try{await api(action,{id:taskId});await markNoticeReadById(noticeId,false);toast('任务状态已更新');await load({silent:true});await loadNotifications(false);await refreshNoticeCenterIfOpen()}catch(e){toast(e.message)}}
async function handleNoticeAction(id,action){try{await api('handle_notification',{id,handle_action:action});toast('已处理');await load({silent:true});await loadNotifications(false);await refreshNoticeCenterIfOpen()}catch(e){toast(e.message)}}
async function snoozeNotice(id,minutes){try{await api('snooze_notification',{id,minutes});toast('已稍后提醒');await loadNotifications(false);await refreshNoticeCenterIfOpen()}catch(e){toast(e.message)}}
async function markNoticeReadById(id,refresh=true){id=String(id||'');if(/^\d+$/.test(id))await api('mark_read',{id}).catch(e=>toast(e.message));if(id.startsWith('task_'))await api('mark_task_read',{id:id.replace('task_','')}).catch(e=>toast(e.message));if(refresh){toast('已标记已读');await load({silent:true});await loadNotifications(false);await refreshNoticeCenterIfOpen()}}
async function markAllNoticesRead(){await api('mark_all_read_history',{}).catch(e=>toast(e.message));toast('历史通知已标记已读，待处理事项不受影响');await load({silent:true});await loadNotifications(false);await refreshNoticeCenterIfOpen()}
async function markSelectedNoticesRead(){let ids=$all('[data-notice-check]:checked').map(x=>x.dataset.noticeCheck).filter(id=>/^\d+$/.test(String(id)));if(!ids.length){toast('请先勾选通知');return}for(const id of ids)await api('mark_read',{id}).catch(e=>toast(e.message));toast('已标记 '+ids.length+' 条通知');await loadNotifications(false);await refreshNoticeCenterIfOpen()}
async function cleanupDuplicateNotifications(){if(!confirm('清理重复通知只会软归档重复历史，不会删除派工任务。继续？'))return;try{let r=await api('cleanup_duplicate_notifications',{});toast('已清理 '+(r.archived||0)+' 条重复通知');await loadNotifications(false);await refreshNoticeCenterIfOpen()}catch(e){toast(e.message)}}
async function loadNotifications(mark=false){let n=await api('list_notifications',{mark:mark?1:0}).catch(()=>null);if(!n)return;if(state.data){state.data.notifications=n;updateDispatchMessageMeta()}else{$('#notifyCount').textContent=n.unread_count;renderNotices(n.items)}}
async function loadOnlineStatus(){let o=await api('online_status').catch(()=>null);if(!o)return;$('#onlineCount').textContent=String(o.count||0);let rows=o.people||[],box=$('#onlinePanel');if(!box)return;box.innerHTML=rows.length?rows.map(u=>`<div class="onlineRow"><b>${esc(u.user_name||u.name||'-')}</b><span>${esc(u.status||'在线')}</span><span>${esc(u.current_module||'派工待办')}</span><span>${esc(u.device_type||'')}</span><small>上线：${esc(u.login_time||'')} · 最后活跃：${esc(u.last_active_time||'')} · 在线：${esc(u.online_text||'-')} · ${esc(u.department||'')}</small></div>`).join(''):'<div class="onlineRow"><b>暂无在线记录</b><span></span></div>'}
function openForm(mode){state.mode=mode;const map={personal:['新增个人','自己创建、自己负责，可直接执行。'],dispatch:['新增派工','派给一个执行人，默认待接收。'],multi:['多人','生成一个组和多条子任务。'],plan:['计划派工','未来日期默认不到当天不显示。'],recurring:['周期派工','保存规则后每天自动检查生成。'],columns:['列设置','保存当前账号桌面列偏好。'],mobileColumns:['手机列设置','保存当前账号手机列偏好。'],permissions:['权限设置','管理员可保存派工模块扩展配置。'],logs:['日志 / 备份','查看近期日志或生成备份文件。']};$('#formTitle').textContent=map[mode][0];$('#formHint').textContent=map[mode][1];$('#formSave').style.display='inline-flex';if(['columns','mobileColumns','permissions','logs'].includes(mode))renderToolForm(mode);else renderTaskForm(mode);$('#formModal').showModal()}
function renderTaskForm(mode){let isMulti=mode==='multi'||mode==='recurring';$('#formBody').innerHTML=`<div class="grid2"><label class="field"><span>标题</span><input id="f_title"></label><label class="field"><span>项目</span><input id="f_project"></label></div><div class="grid3"><label class="field"><span>优先级</span><select id="f_priority"><option value="normal">普通</option><option value="important">重要</option><option value="urgent">紧急</option><option value="today">今日</option></select></label><label class="field"><span>任务日期</span><input id="f_date" type="date" value="${mode==='plan'?nextDay():state.date}"></label><label class="field"><span>截止时间 *</span><input id="f_due" type="datetime-local" required></label></div>${mode==='personal'?'':assigneePickerHtml(isMulti)}<label class="field"><span>说明</span><textarea id="f_desc"></textarea></label>${mode==='recurring'?recurringFields():''}`;$('#formSave').onclick=saveForm}
function assigneePickerHtml(isMulti){if(!isMulti)return `<label class="field"><span>负责人</span><select id="f_assignees">${userOptions()}</select></label>`;return `<div class="field"><span>执行人</span><div id="f_assignees" class="permCheckGrid assigneeCheckGrid">${state.users.map(u=>`<label class="permCheckChip"><input type="checkbox" value="${u.id}"><span>${esc(u.name)}</span><small>${esc(u.department||'-')}</small></label>`).join('')}</div></div>`}
function selectedAssigneeIds(){let box=$('#f_assignees');if(!box)return [];if(box.tagName==='SELECT')return $all('#f_assignees option:checked').map(o=>o.value);return $all('#f_assignees input[type="checkbox"]:checked').map(o=>o.value)}
function recurringFields(){return `<div class="panel"><h4>周期规则</h4><div class="grid3"><label class="field"><span>频率</span><select id="f_freq"><option value="daily">每天</option><option value="weekly">每周几</option><option value="monthly">每月几号</option></select></label><label class="field"><span>每周几 1-7</span><input id="f_weekdays" placeholder="1,2,5"></label><label class="field"><span>每月几号</span><input id="f_monthdays" placeholder="1,15,28"></label></div><div class="grid2"><label class="field"><span>开始日期</span><input id="f_start" type="date" value="${state.date}"></label><label class="field"><span>结束日期</span><input id="f_end" type="date"></label></div></div>`}
function nextDay(){let d=new Date();d.setDate(d.getDate()+1);return localDateString(d)}
async function saveForm(){try{let m=state.mode;if(m==='columns'||m==='mobileColumns')return saveColumns(m);if(m==='permissions')return savePerms();if(m==='logs')return runBackup();let data={title:$('#f_title').value,project:$('#f_project').value,priority:$('#f_priority').value,task_date:$('#f_date').value,due_at:$('#f_due').value,description:$('#f_desc').value};if(!String(data.due_at||'').trim()){toast('派工待办必须填写截止时间');$('#f_due').focus();return}if(m==='personal')await api('create_task',Object.assign(data,{task_type:'personal'}));if(m==='dispatch')await api('create_task',Object.assign(data,{task_type:'dispatch',assigned_to:$('#f_assignees').value}));if(m==='plan')await api('create_plan',Object.assign(data,{assigned_to:$('#f_assignees').value}));if(m==='multi')await api('create_multi',Object.assign(data,{assignee_ids:selectedAssigneeIds()}));if(m==='recurring')await api('create_recurring',Object.assign(data,{assignee_ids:selectedAssigneeIds(),freq:$('#f_freq').value,weekdays:csv('#f_weekdays'),monthdays:csv('#f_monthdays'),start_date:$('#f_start').value,end_date:$('#f_end').value}));$('#formModal').close();toast('已保存');load()}catch(e){toast(e.message)}}
function csv(s){return ($(s).value||'').split(',').map(x=>parseInt(x.trim(),10)).filter(Boolean)}
function renderToolForm(mode){if(mode==='logs'){$('#formBody').innerHTML='<div class="panel"><h4>日志与备份</h4><div class="logCategoryBar"><button class="active" type="button" data-log-category="online">在线时间</button><button type="button" data-log-category="backup">备份/恢复</button></div><div data-log-panel="online"><div class="onlinePicker" id="onlineUserPicker"></div><div class="onlineChart" id="onlineChartBox">加载中</div><div class="logs" id="onlineLogsBox"></div></div><div data-log-panel="backup" style="display:none"><div id="backupCenter">加载中</div></div></div>';$('#formSave').style.display='none';renderOnlineUserPicker();loadOnlineLogs();loadBackupCenter();$all('[data-log-category]').forEach(btn=>btn.onclick=()=>switchLogCategory(btn.dataset.logCategory));return}if(mode==='permissions'){renderPermissionSettings();return}renderColumnSettings(mode)}
function switchLogCategory(cat){$all('[data-log-category]').forEach(b=>b.classList.toggle('active',b.dataset.logCategory===cat));$all('[data-log-panel]').forEach(p=>p.style.display=p.dataset.logPanel===cat?'block':'none')}
function renderOnlineUserPicker(){let box=$('#onlineUserPicker');if(!box)return;box.innerHTML='<label class="permCheckChip"><input type="checkbox" data-online-all checked><span>全部</span></label>'+state.users.map(u=>`<label class="permCheckChip"><input type="checkbox" data-online-user value="${u.id}"><span>${esc(u.name)}</span><small>${esc(u.department||'')}</small></label>`).join('');box.querySelectorAll('input').forEach(i=>i.onchange=()=>{if(i.dataset.onlineAll!==undefined&&i.checked)box.querySelectorAll('[data-online-user]').forEach(x=>x.checked=false);if(i.dataset.onlineUser!==undefined&&i.checked)box.querySelector('[data-online-all]').checked=false;if(!box.querySelector('[data-online-all]').checked&&!box.querySelector('[data-online-user]:checked'))box.querySelector('[data-online-all]').checked=true;loadOnlineLogs()})}
function selectedOnlineUsers(){let all=$('#onlineUserPicker [data-online-all]');if(!all||all.checked)return [];return $all('#onlineUserPicker [data-online-user]:checked').map(x=>Number(x.value))}
async function loadOnlineLogs(){let box=$('#onlineLogsBox'),chart=$('#onlineChartBox');if(box)box.innerHTML='加载中';if(chart)chart.innerHTML='加载中';try{let data=await api('online_logs',{user_ids:selectedOnlineUsers()});let summary=data.summary||[],sessions=data.sessions||[];renderOnlineChart(summary);if(box)box.innerHTML=sessions.map(onlineLogHtml).join('')||'<div class="empty">暂无在线日志</div>'}catch(e){if(box)box.innerHTML='<div class="empty">'+esc(e.message)+'</div>';if(chart)chart.innerHTML=''}}
function renderOnlineChart(rows){let box=$('#onlineChartBox');if(!box)return;let max=Math.max(1,...rows.map(r=>Number(r.online_seconds||0)));box.innerHTML=rows.length?rows.map(r=>`<div class="onlineBarRow"><b title="${esc(r.department||'')}">${esc(r.user_name||'-')}</b><div class="onlineBarTrack"><div class="onlineBarFill" style="width:${Math.max(3,Math.round(Number(r.online_seconds||0)/max*100))}%"></div></div><span>${esc(r.online_text||'0分')}</span></div>`).join(''):'<div class="empty">暂无在线数据</div>'}
function onlineLogHtml(u){return `<div class="log"><b>${esc(u.user_name||'')}</b> <span>${esc(u.department||'')}</span><br><em>上线：${esc(u.login_time||'')} · 最后活跃：${esc(u.last_active_time||'')}</em><div>在线时长：${esc(u.online_text||'-')} · 模块：${esc(u.current_module||'')} · 设备：${esc(u.device_type||'')}</div></div>`}
function logHtml(l){return `<div class="log"><b>${esc(l.user_name||'')}</b> ${esc(l.action_type)} ${l.field_name?esc(l.field_name):''}<br><em>${esc(l.created_at||'')}</em><div>${esc(l.old_value||'')} → ${esc(l.new_value||'')}</div></div>`}
async function renderColumnSettings(mode){let scope=mode==='mobileColumns'?'mobile':'desktop';$('#formBody').innerHTML='<div class="panel"><h4>'+(scope==='mobile'?'手机列设置':'桌面列设置')+'</h4><div class="empty">正在读取'+(scope==='mobile'?'手机':'桌面')+'列配置...</div></div>';try{let p=await api('get_table_prefs',{scope});state.editColumns=(p.columns||[]).sort((a,b)=>(Number(a.order)||0)-(Number(b.order)||0));state.editColorPrefs=Object.assign(defaultColorPrefs(),p.color_prefs||{})}catch(e){state.editColumns=state.columns.map(c=>Object.assign({},c));state.editColorPrefs=Object.assign(defaultColorPrefs(),state.colorPrefs||{});toast(e.message)}renderColumnSettingsBody(mode,scope)}
function renderColumnSettingsBody(mode,scope){let title=scope==='mobile'?'手机列设置':'桌面列设置',hint=scope==='mobile'?'手机列宽单位为 px，可直接手输数字；完成/优先级/标题/项目优先显示，其余列向右滑动查看。':'顺序数字越小越靠前；列宽、显示状态和自定义列保存到当前账号。',cols=state.editColumns||state.columns;$('#formBody').innerHTML='<div class="panel columnSettingsPanel"><div class="columnSettingsHead"><h4>'+title+'</h4><span>'+hint+'</span></div><div class="columnGrid columnGridHeader"><span>显示</span><span>列名</span><span>顺序</span><span>列宽</span><span>类型</span><span>操作</span></div><div data-column-editor>'+cols.map((c,i)=>columnEditorRow(c,i,scope)).join('')+'</div><div class="columnCustomAdd"><input id="newColLabel" placeholder="新增列名"><select id="newColType"><option value="text">单行文字</option><option value="textarea">多行文字</option><option value="number">数字</option><option value="date">日期</option><option value="datetime">日期时间</option><option value="select">下拉选项</option><option value="user">人员</option></select><input id="newColOptions" placeholder="下拉选项，用逗号分隔"><button class="btn" type="button" id="addCustomCol">新增</button></div><p class="columnSettingsHint">保存后立即按当前账号生效；手机端支持横向滑动查看后续列。</p></div>'+colorSettingsHtml(state.editColorPrefs||state.colorPrefs);$('#addCustomCol').onclick=async()=>{let label=$('#newColLabel').value.trim();if(!label)return toast('请输入列名');let opts=($('#newColOptions').value||'').split(',').map(s=>s.trim()).filter(Boolean);await api('save_custom_field',{field_label:label,field_type:$('#newColType').value,options:opts,sort_order:cols.length*10});renderColumnSettings(mode)};$all('[data-delete-custom]').forEach(btn=>btn.onclick=()=>{btn.dataset.clicked='1';btn.closest('[data-col-editor]').style.opacity='.45';btn.textContent='保存后停用'});$all('[data-color-pref]').forEach(inp=>inp.oninput=()=>{state.editColorPrefs=readColorPrefs();updateColorPreview(state.editColorPrefs)});$('[data-icon-style]')?.addEventListener('change',()=>{state.editColorPrefs=readColorPrefs();updateColorPreview(state.editColorPrefs)});$('[data-ref-chip-mode]')?.addEventListener('change',()=>{state.editColorPrefs=readColorPrefs();updateColorPreview(state.editColorPrefs)});$('#formSave').onclick=()=>saveColumns(mode);updateColorPreview(state.editColorPrefs||state.colorPrefs)}
function colorSettingsHtml(source){let p=Object.assign(defaultColorPrefs(),source||state.colorPrefs||{});let items=[['assignee','负责人名字'],['creator','派工来自名字'],['method','方式文字'],['mention_naming','@命名'],['mention_bom','@BOM'],['mention_quote','@报价'],['mention_plm','@PLM'],['mention_snapshot','@快照'],['mention_material','@资料'],['mention_dispatch','@派工'],['mention_opportunity','@商机'],['overdue_bg','逾期未完成填充'],['overdue_line','逾期左侧线条'],['done_bg','已完成填充']];return `<div class="panel"><h4>表格数据颜色 / 按钮样式</h4><div class="colorPrefGrid">${items.map(x=>`<label><span>${x[1]}</span><input type="color" data-color-pref="${x[0]}" value="${esc(p[x[0]])}"></label>`).join('')}<label><span>操作符号样式</span><select data-icon-style><option value="minimal" ${p.icon_style==='minimal'?'selected':''}>细符号</option><option value="compact" ${p.icon_style==='compact'?'selected':''}>紧凑符号</option><option value="soft" ${p.icon_style==='soft'?'selected':''}>柔和色块</option><option value="outline" ${p.icon_style==='outline'?'selected':''}>描边符号</option><option value="solid" ${p.icon_style==='solid'?'selected':''}>实色符号</option><option value="symbol" ${p.icon_style==='symbol'?'selected':''}>圆形符号</option></select></label><label><span>@标签显示模式</span><select data-ref-chip-mode><option value="minimal" ${p.ref_chip_mode==='minimal'?'selected':''}>极简</option><option value="standard" ${p.ref_chip_mode==='standard'?'selected':''}>标准</option><option value="emphasis" ${p.ref_chip_mode==='emphasis'?'selected':''}>强调</option></select></label></div><div class="colorPreviewLine" id="colorPreviewLine"></div><p style="color:var(--muted);font-size:12px">操作按钮只显示符号；蓝色查看详情，橙色催办，红色删除。样式保存到当前账号。</p></div>`}
function readColorPrefs(){let p=Object.assign(defaultColorPrefs(),state.colorPrefs||{});$all('[data-color-pref]').forEach(inp=>p[inp.dataset.colorPref]=inp.value||p[inp.dataset.colorPref]);let s=$('[data-icon-style]');if(s)p.icon_style=s.value||p.icon_style;let m=$('[data-ref-chip-mode]');if(m)p.ref_chip_mode=m.value||p.ref_chip_mode;return p}
function updateColorPreview(source){let p=Object.assign(defaultColorPrefs(),source||state.colorPrefs||{}),box=$('#colorPreviewLine');if(!box)return;let old=state.colorPrefs;state.colorPrefs=p;let actions=`<span class="rowActions ${actionIconClass()}"><button class="btn mini iconBtn action-detail" type="button">${actionIcon('detail')}</button><button class="btn mini iconBtn action-urge" type="button">${actionIcon('urge')}</button><button class="btn mini iconBtn action-danger" type="button">${actionIcon('delete')}</button></span>`;state.colorPrefs=old;box.innerHTML=`<span style="color:${p.assignee}">负责人 QL</span><span style="color:${p.creator}">派工来自 Admin</span><span style="color:${p.method}">多人</span>${actions}<span class="ref-chip ref-chip-naming" style="color:${p.mention_naming}"><span class="ref-chip-bar"></span><span class="ref-chip-type">@命名</span><span class="ref-chip-code">61.02366</span></span><span class="ref-chip ref-chip-bom" style="color:${p.mention_bom}"><span class="ref-chip-bar"></span><span class="ref-chip-type">@BOM</span><span class="ref-chip-code">B-001</span></span><span class="ref-chip ref-chip-quote" style="color:${p.mention_quote}"><span class="ref-chip-bar"></span><span class="ref-chip-type">@报价</span><span class="ref-chip-code">Q-001</span></span><span class="ref-chip ref-chip-plm" style="color:${p.mention_plm}"><span class="ref-chip-bar"></span><span class="ref-chip-type">@PLM</span><span class="ref-chip-code">P-001</span></span><span class="ref-chip ref-chip-snapshot" style="color:${p.mention_snapshot}"><span class="ref-chip-bar"></span><span class="ref-chip-type">@快照</span><span class="ref-chip-code">32.04526</span></span><span style="background:${p.overdue_bg};border-left:4px solid ${p.overdue_line}">逾期未完成</span><span style="background:${p.done_bg}">已完成</span>`}
function columnEditorRow(c,i,scope='desktop'){let min=scope==='mobile'?24:Number(c.minWidth||44),max=scope==='mobile'?520:Number(c.maxWidth||760);return `<div class="columnGrid columnEditorRow" data-col-editor="${esc(c.key)}"><div><label title="显示/隐藏"><input type="checkbox" data-col-visible ${Number(c.visible)!==0?'checked':''}></label></div><div><input data-col-label value="${esc(c.label)}" title="列名"></div><div><input data-col-order type="number" value="${Number(c.order)||((i+1)*10)}" title="顺序"></div><div><input data-col-width type="number" min="${min}" max="${max}" step="1" value="${Number(c.width||defaultColWidth(c.key))}" title="列宽 px"></div><div class="columnEditorType" title="${esc(c.type||'text')}">${esc(c.type||'text')}</div><div class="columnEditorActions">${c.custom?'<button class="btn mini red" type="button" data-delete-custom="'+esc(c.field_key||c.key.replace(/^custom_/,''))+'">停用</button>':'<span></span>'}</div></div>`}
async function saveColumns(mode){let scope=mode==='mobileColumns'?'mobile':'desktop',editCols=state.editColumns||state.columns,next=[];$all('[data-col-editor]').forEach(box=>{let key=box.dataset.colEditor,col=editCols.find(c=>c.key===key)||{key};next.push(Object.assign({},col,{visible:box.querySelector('[data-col-visible]').checked?1:0,label:box.querySelector('[data-col-label]').value,width:Number(box.querySelector('[data-col-width]').value||defaultColWidth(key)),order:Number(box.querySelector('[data-col-order]').value||0)}))});for(const btn of $all('[data-delete-custom]')){if(btn.dataset.clicked){await api('delete_custom_field',{field_key:btn.dataset.deleteCustom})}}let savedColors=readColorPrefs();await api('save_table_prefs',{scope,columns:next,color_prefs:savedColors});state.editColumns=null;state.editColorPrefs=null;if(scope===state.scope){state.colorPrefs=savedColors;await loadTablePrefs();renderAll()}else{await loadTablePrefs();renderAll()}toast((scope==='mobile'?'手机':'桌面')+'列设置已保存');$('#formModal').close()}
function normalizePermissionSettings(p){let perms=p?.permissions||p||{};if(perms.permissions)perms=perms.permissions;let visibility={};Object.entries(perms.visibility||{}).forEach(([uid,rule])=>{visibility[String(uid)]={allow:(rule?.allow||[]).map(String),deny:(rule?.deny||[]).map(String)}});return {note:perms.note||'',visibility}}
async function renderPermissionSettings(){let p=await api('get_permissions').catch(()=>({permissions:{}}));let perms=normalizePermissionSettings(p);let rows=state.users.map(u=>permissionRow(u,perms.visibility[String(u.id)]||{})).join('');$('#formBody').innerHTML=`<div class="panel"><h4>人员可见规则</h4><p style="color:var(--muted);font-size:12px">默认只能看自己相关待办。允许名单会额外开放 B 的任务；禁止名单会从可见范围里排除 B。管理员默认可看全部，但禁止名单同样生效。</p><div class="logs">${rows}</div></div><div class="panel"><h4>备注</h4><textarea id="permText" placeholder="例如：A 可以看 B；A 不能看 C">${esc(perms.note||'')}</textarea></div>`;$('#formSave').onclick=savePerms}
function permissionRow(viewer,rule){let allow=(rule.allow||[]).map(String),deny=(rule.deny||[]).map(String);return `<div class="log permMatrixRow" data-perm-user="${viewer.id}"><b>${esc(viewer.name)} / ${esc(viewer.department||'-')}</b><div class="permCheckBlock"><span>允许额外查看</span><div class="permCheckGrid" data-perm-allow>${permUserChecks(allow,viewer.id,'allow')}</div></div><div class="permCheckBlock"><span>禁止查看</span><div class="permCheckGrid deny" data-perm-deny>${permUserChecks(deny,viewer.id,'deny')}</div></div></div>`}
function permUserChecks(selected=[],viewerId=0,type='allow'){return state.users.filter(u=>String(u.id)!==String(viewerId)).map(u=>`<label class="permCheckChip ${type==='deny'?'deny':''}"><input type="checkbox" value="${u.id}" ${selected.includes(String(u.id))?'checked':''}><span>${esc(u.name)}</span><small>${esc(u.department||'-')}</small></label>`).join('')}
async function savePerms(){let visibility={};$all('[data-perm-user]').forEach(box=>{let uid=box.dataset.permUser;visibility[uid]={allow:$all('[data-perm-allow] input:checked',box).map(o=>Number(o.value)),deny:$all('[data-perm-deny] input:checked',box).map(o=>Number(o.value))}});await api('save_permissions',{permissions:{note:$('#permText')?.value||'',visibility}});toast('权限配置已保存');$('#formModal').close();load()}
async function loadBackupCenter(){let box=$('#backupCenter');if(!box)return;box.innerHTML='加载中';try{let data=await api('list_backups');renderBackupCenter(data)}catch(e){box.innerHTML='<div class="empty">'+esc(e.message)+'</div>'}}
function renderBackupCenter(data){let box=$('#backupCenter'),s=data.settings||{},items=data.items||[];if(!box)return;box.innerHTML=`<div class="panel"><h4>自动备份设置</h4><div class="grid3"><label class="field"><span>启用自动备份</span><select id="backupEnabled"><option value="1" ${Number(s.enabled)?'selected':''}>启用</option><option value="0" ${!Number(s.enabled)?'selected':''}>停用</option></select></label><label class="field"><span>间隔小时</span><input id="backupInterval" type="number" min="1" max="168" value="${esc(s.interval_hours||24)}"></label><label class="field"><span>保留份数</span><input id="backupRetention" type="number" min="3" max="100" value="${esc(s.retention_count||20)}"></label></div><p style="color:var(--muted);font-size:12px">最后自动备份：${esc(s.last_auto_at||'尚未执行')}。打开/同步派工列表时会静默检查是否到期。</p><button class="btn" type="button" id="saveBackupSettings">保存自动备份设置</button></div><div class="panel"><h4>全量备份</h4><button class="btn primary" id="backupBtn" type="button">立即生成全量备份</button><span id="backupOut" style="margin-left:8px;color:var(--muted);font-size:12px"></span></div><div class="panel"><h4>上传备份文件</h4><div class="grid2"><input id="backupUploadFile" type="file" accept=".json,.zip,application/json,application/zip,application/x-zip-compressed"><button class="btn" id="uploadBackupBtn" type="button">上传备份文件</button></div><p style="color:var(--muted);font-size:12px">支持本系统导出的 JSON 或包含有效备份 JSON 的 ZIP；上传后先校验，再加入下方备份列表，恢复时从列表选择。</p><div id="uploadBackupOut" style="color:var(--muted);font-size:12px"></div></div><div class="panel"><h4>备份文件 / 恢复</h4><div class="logs">${items.map(backupRowHtml).join('')||'<div class="empty">暂无备份文件</div>'}</div></div>`;$('#backupBtn').onclick=runBackup;$('#saveBackupSettings').onclick=saveBackupSettings;$('#uploadBackupBtn').onclick=uploadBackup;$all('[data-restore-backup]').forEach(btn=>btn.onclick=()=>restoreBackup(btn.dataset.restoreBackup))}
function backupRowHtml(b){return `<div class="log"><b>${esc(b.name)}</b><br><em>${esc(b.type||'JSON')} · ${esc(b.created_at||'')} · ${esc(b.reason||'')} · ${fileSize(b.size||0)}</em><div style="margin-top:6px;display:flex;gap:6px;flex-wrap:wrap"><button class="btn mini red" type="button" data-restore-backup="${esc(b.name)}">恢复此备份</button><span style="color:var(--muted);font-size:12px">恢复前会自动生成 pre_restore 备份，失败会自动回滚。</span></div></div>`}
async function saveBackupSettings(){let r=await api('save_backup_settings',{enabled:$('#backupEnabled').value==='1'?1:0,interval_hours:$('#backupInterval').value,retention_count:$('#backupRetention').value});toast('自动备份设置已保存');loadBackupCenter()}
async function runBackup(){let out=$('#backupOut');if(out)out.textContent='备份中...';let r=await api('backup').catch(e=>({error:e.message}));if(out)out.textContent=r.error?esc(r.error):'备份文件：'+esc(r.name||r.file||'');toast(r.error||'备份完成');loadBackupCenter()}
async function uploadBackup(){let input=$('#backupUploadFile'),out=$('#uploadBackupOut');if(!input?.files?.[0])return toast('请选择备份 JSON 或 ZIP 文件');if(out)out.textContent='上传并校验中...';let r=await api('upload_backup',{},input.files[0]).catch(e=>({error:e.message}));if(out)out.textContent=r.error?esc(r.error):'上传完成：'+esc(r.name||'');toast(r.error||'上传完成');if(!r.error)await loadBackupCenter()}
async function restoreBackup(name){if(!confirm('确认恢复此备份？\\n\\n'+name+'\\n\\n系统会先自动生成恢复前备份；恢复失败会自动回滚。'))return;let r=await api('restore_backup',{name}).catch(e=>({error:e.message}));if(r.error){toast(r.error);return}toast('恢复完成，恢复前备份：'+(r.pre_restore_backup||''));await loadBackupCenter();await load()}
async function openDetail(id){if(!id)return;state.memberDetailMode=false;try{let d=await api('task_detail',{id});let t=d.task||{};if(isMultiDetail(d)){d=await api('multi_group_detail',{id});state.currentDetail=d;renderMultiDetail(d)}else{state.currentDetail=d;renderDetail(d)}$('#detailModal').showModal();load({silent:true})}catch(e){toast(e.message)}}
function isMultiDetail(d){let t=d?.task||{};return String(t.dispatch_mode||'')==='multi'||Number(t.parent_group_id||0)>0||!!d?.group}
function renderDetail(d){let t=d.task;$('#detailBody').className='modalBody detailBody';$('#detailTitle').textContent=t.title||'任务详情';$('#detailHint').textContent=`${esc(t.task_no||'')} · ${esc(t.method_label||'派工待办')} · ${statusText(t.status)}`;$('#detailBadges').innerHTML=detailBadges(t);$('#detailBody').innerHTML=detailHtml(d);$('#detailFoot').innerHTML=detailFooter(t);bindDetailEvents();setDetailTab(state.detailTab||'detail',false);restoreDetailSaveStatuses();renderDetailLogs('all')}
function renderMultiDetail(d){state.memberDetailMode=false;let g=d.group||{},t=d.task||{},members=d.members||[];$('#detailBody').className='modalBody detailBody multiDetailBody';$('#detailTitle').textContent=g.title||t.title||'多人派工';$('#detailHint').textContent=`${esc(g.group_no||'')} · 多人派工 · ${statusText(g.status||t.status||'in_progress')}`;$('#detailBadges').innerHTML=`<span class="dtag purple">多人</span><span class="dtag blue">${statusText(g.status||t.status||'in_progress')}</span><span class="dtag green">${Number(g.done_count||0)}/${Number(g.total_count||members.length||0)} 已完成</span>${g.due_at?`<span class="dtag ${esc(dueClass({due_at:g.due_at,status:g.status||''}))}">截止 ${esc(formatDue(g.due_at))}</span>`:''}`;$('#detailBody').innerHTML=multiDetailHtml(d);$('#detailFoot').innerHTML=detailFooter(t);bindDetailEvents();setDetailTab(state.detailTab||'detail',false);restoreDetailSaveStatuses();renderDetailLogs('all')}
function multiDetailHtml(d){let t=d.task||{},imgs=(d.attachments||[]).filter(a=>a.file_kind==='image'),atts=(d.attachments||[]).filter(a=>a.file_kind==='attachment'),tabs=[['detail','详情',multiDashboardHtml(d)],['progress','进度',progressHtml(t)+timelineHtml(d.comments||[])],['images','图片',imageUploadHtml(imgs)],['attachments','附件',attachmentHtml(atts)],['steps','步骤',stepsHtml(d.steps||[])],['logs','日志',logsHtml(d.logs||[])]];return `${summaryHtml(t)}<nav class="detailTabs">${tabs.map(x=>`<button type="button" data-detail-tab="${x[0]}">${x[1]}</button>`).join('')}</nav>${tabs.map(x=>`<div class="detailPane" data-detail-pane="${x[0]}">${x[2]}</div>`).join('')}`}
function multiDashboardHtml(d){let g=d.group||{},members=d.members||[],total=Number(g.total_count||members.length||0),done=Number(g.done_count||0),pending=Number(g.pending_count||0),running=Number(g.running_count||0),overdue=Number(g.overdue_count||0),progress=total?Math.floor(done*100/total):0;return `<section class="multiOverview">${[['总人数',total],['已完成',done],['待接收',pending],['进行中',running],['逾期',overdue],['总进度',progress+'%']].map(x=>`<article><span>${x[0]}</span><strong>${esc(x[1])}</strong></article>`).join('')}</section><section class="detailSection"><h4>成员执行列表 <small>${done}/${total} 已完成</small></h4><div class="multiMemberBoard"><div class="multiMemberHead"><span>执行人</span><span>状态</span><span>进度</span><span>截止日期</span><span>完成时间</span><span>操作</span></div>${members.map(multiMemberRow).join('')||'<div class="empty">暂无成员</div>'}</div></section>${multiBaseInfoHtml(d)}<section class="detailSection"><h4>组进度记录</h4><div class="multiTimeline">${(d.comments||[]).slice(0,20).map(c=>`<div class="log"><b>${esc(c.user_name||'')}</b><br><em>${esc(c.created_at||'')}</em><div>${esc(c.comment||'')}</div></div>`).join('')||'<div class="empty">暂无组进度记录</div>'}</div></section>`}
function multiMemberRow(m){let id=Number(m.task_id),done=m.status==='done',cls=[done?'done':'',m.is_overdue?'overdue':'',m.is_current_user?'mine':''].filter(Boolean).join(' '),actions=[];if(done){actions.push(`<button class="btn mini" onclick="openMemberTaskDetail(${id})">查看</button>`)}else if(m.is_current_user){if(m.can_accept)actions.push(`<button class="btn mini" onclick="multiMemberAccept(${id})">接收任务</button>`);actions.push(`<button class="btn mini primary" onclick="multiMemberComplete(${id})">完成我的任务</button>`);if(m.can_write_progress)actions.push(`<button class="btn mini" onclick="multiMemberProgress(${id})">写进度</button>`)}else{actions.push(`<button class="btn mini" onclick="openMemberTaskDetail(${id})">打开</button>`);if(m.can_urge)actions.push(`<button class="btn mini" onclick="multiMemberUrge(${id})">催办</button>`);if(m.can_admin_complete)actions.push(`<button class="btn mini" onclick="multiMemberAdminComplete(${id})">代标完成</button>`)}return `<div class="multiMemberRow ${cls}"><div class="multiMemberName"><b>${esc(m.assigned_name||'未分配')}</b><small>${esc(m.task_no||'')}</small></div><span data-label="状态">${statusText(m.status)}</span><span data-label="进度">${Number(m.progress||0)}%</span><span data-label="截止">${esc(formatDue(m.due_at)||'—')}</span><span data-label="完成">${esc(m.completed_at||'—')}</span><div class="multiMemberActions">${actions.join('')}</div></div>`}
function multiBaseInfoHtml(d){let g=d.group||{},t=d.task||{},items=[['任务标题',g.title||t.title],['项目 / 任务内容',g.project||t.project],['详细说明',g.description||t.description],['状态',statusText(g.status||t.status)],['优先级',prio(t.priority||'normal')],['负责人','多人'],['任务日期',g.task_date||t.task_date],['截止日期',formatDue(g.due_at||t.due_at)],['进度',Number(g.progress||0)+'%'],['方式','多人派工'],['派工来自',g.creator_name||t.creator_name],['关联系统',t.linked_system||'—'],['关联标题',t.linked_title||'—']];return `<details class="multiFold"><summary><span>基础信息</span><span>展开</span></summary><div class="multiInfoGrid">${items.map(x=>`<article><span>${x[0]}</span><b>${esc(x[1]||'—')}</b></article>`).join('')}</div></details>`}
function multiMemberName(id){let m=(state.currentDetail?.members||[]).find(x=>Number(x.task_id)===Number(id));return m?.assigned_name||'成员'}
async function refreshMultiMemberAction(promise,msg){try{await promise;if(msg)toast(msg);await refreshDetail(true);load({silent:true})}catch(e){toast(e.message||'操作失败')}}
function multiMemberAccept(id){refreshMultiMemberAction(api('multi_member_accept',{id}),'已接收任务')}
function multiMemberComplete(id){refreshMultiMemberAction(api('multi_member_complete',{id}),'已完成我的任务')}
function multiMemberAdminComplete(id){let name=multiMemberName(id);if(!confirm(`确认将【${name}】的任务标记为已完成？`))return;refreshMultiMemberAction(api('multi_member_admin_complete',{id}),'已代标完成')}
function multiMemberUrge(id){let note=prompt('催办说明','请尽快处理这条派工');if(note===null)return;refreshMultiMemberAction(api('multi_member_urge',{id,note}),'已催办')}
async function multiMemberProgress(id){try{state.memberDetailMode=true;let d=await api('multi_member_detail',{id});state.currentDetail=d;renderDetail(d);setDetailTab('progress',false);$('#detailModal').showModal();requestAnimationFrame(()=>{$('#commentText')?.focus()})}catch(e){toast(e.message||'打开进度失败')}}
async function openMemberTaskDetail(id){try{state.memberDetailMode=true;let d=await api('multi_member_detail',{id});state.currentDetail=d;renderDetail(d);$('#detailModal').showModal()}catch(e){toast(e.message||'打开成员任务失败')}}
function detailBadges(t){let cls={pending_accept:'blue',accepted:'blue',in_progress:'blue',paused:'orange',submitted:'purple',done:'green',cancelled:'gray'}[t.status]||'gray',dueCls={overdue:'red',due_soon:'orange',due_today:'orange'}[t.due_state]||'';return `<span class="dtag ${cls}">${statusText(t.status)}</span><span class="dtag">${prio(t.priority)}</span>${t.due_label?`<span class="dtag ${dueCls}">${esc(t.due_label)}</span>`:''}${t.dispatch_mode==='multi'?'<span class="dtag purple">多人</span>':''}`}
function detailHtml(d){let t=d.task,imgs=(d.attachments||[]).filter(a=>a.file_kind==='image'),atts=(d.attachments||[]).filter(a=>a.file_kind==='attachment'),tabs=[['detail','详情',baseEditHtml(t)+linkedHtml(t)+groupHtml(d)],['progress','进度',progressHtml(t)+timelineHtml(d.comments||[])],['images','图片',imageUploadHtml(imgs)],['attachments','附件',attachmentHtml(atts)],['steps','步骤',stepsHtml(d.steps||[])],['logs','日志',logsHtml(d.logs||[])]];return `${summaryHtml(t)}<nav class="detailTabs">${tabs.map(x=>`<button type="button" data-detail-tab="${x[0]}">${x[1]}</button>`).join('')}</nav>${tabs.map(x=>`<div class="detailPane" data-detail-pane="${x[0]}">${x[2]}</div>`).join('')}`}
function summaryHtml(t){return `<section class="detailSummary">${[['负责人',t.assignee_name||'—'],['派工人',t.creator_name||'—'],['截止日期',formatDue(t.due_at)],['进度',Number(t.progress||0)+'%'],['创建时间',t.created_at||'—'],['更新时间',t.updated_at||'—']].map(x=>`<article><span>${x[0]}</span><strong class="${x[0]==='截止日期'?esc(dueClass(t)):''}">${esc(x[1])}</strong></article>`).join('')}</section>`}
function baseEditHtml(t){return `<section class="detailSection"><h4>基础信息</h4><div class="detailEditGrid"><div class="detailStack"><label class="field"><span>任务标题</span><input data-detail-field="title" value="${esc(t.title)}"></label><label class="field"><span>项目 / 任务内容</span><textarea class="tall" data-detail-field="project">${esc(t.project||'')}</textarea></label><label class="field"><span>详细说明</span><textarea data-detail-field="description">${esc(t.description||'')}</textarea></label></div><div class="detailSideGrid"><label class="field"><span>状态</span><select data-detail-field="status">${statusOptions(t.status)}</select></label><label class="field"><span>优先级</span><select data-detail-field="priority">${['today','urgent','important','normal'].map(v=>`<option value="${v}" ${v===t.priority?'selected':''}>${prio(v)}</option>`).join('')}</select></label><label class="field"><span>负责人</span><select data-detail-field="assigned_to">${userOptions(t.assigned_to)}</select></label><label class="field"><span>任务日期</span><input type="date" data-detail-field="task_date" value="${esc(t.task_date||'')}"></label><label class="field wide"><span>截止日期 *</span><input type="datetime-local" data-detail-field="due_at" required value="${esc((t.due_at||'').replace(' ','T').slice(0,16))}"></label><label class="field wide"><span>进度</span><div class="progressLine"><input type="range" min="0" max="100" data-detail-progress value="${Number(t.progress||0)}"><input type="number" min="0" max="100" data-detail-field="progress" value="${Number(t.progress||0)}"></div></label><label class="field"><span>方式</span><select data-detail-field="dispatch_mode">${methodOptions(methodValue(t))}</select></label><label class="field"><span>派工来自</span><input value="${esc(t.creator_name||'')}" readonly></label><label class="field"><span>关联系统</span><input value="${esc(t.linked_system||'')}" readonly></label><label class="field"><span>关联标题</span><input value="${esc(t.linked_title||'')}" readonly></label></div></div></section>`}
function statusOptions(v){return ['pending_accept','accepted','in_progress','paused','submitted','returned','rejected','done','cancelled'].map(s=>`<option value="${s}" ${s===v?'selected':''}>${statusText(s)}</option>`).join('')}
function imageUploadHtml(imgs){return `<section class="detailSection"><div class="imageUploadBar"><div class="imageDrop" id="imgDrop"><div><strong>图片</strong><span>拖入 / 粘贴 / 选择，自动压缩，7天后删除</span></div><input id="imgFile" type="file" accept="image/*"><button class="btn mini" type="button" data-choose-image>上传</button></div></div><div class="imageUploadStatus" id="imageUploadStatus"></div><div class="mediaGrid">${imgs.map(imageCard).join('')||'<div class="empty">暂无进度图片</div>'}</div></section>`}
function imageCard(a){return `<article class="mediaCard"><img src="${esc(a.file_path)}" onclick="previewImage('${esc(a.file_path)}')" alt="${esc(a.file_name)}"><b>${esc(a.file_name)}</b><span>${fileSize(a.file_size)} · ${esc(a.created_at||'')}</span><span>${Number(a.is_valid)?'有效至 '+esc(a.expires_at||''):'图片无效'}</span><div class="miniActions"><button class="btn" onclick="previewImage('${esc(a.file_path)}')">预览</button><a class="btn" href="${API}?action=download_attachment&attachment_id=${a.id}" target="_blank">下载</a><button class="btn red" onclick="deleteAttachment(${a.id})">删除</button></div></article>`}
function progressHtml(t){let p=Math.max(0,Math.min(100,Number(t.progress||0)));return `<section class="detailSection"><h4>写进度记录 <small style="float:right;color:var(--muted)">记录人员和时间</small></h4><div class="quickProgress">${[['已开始','已开始处理。','in_progress'],['已出图','已出图，等待确认。','in_progress'],['已报价','已完成报价。','submitted'],['暂停原因','暂停，原因：','paused'],['异常/卡住','异常/卡住：','paused'],['已完成','已完成。','done']].map(x=>`<button type="button" data-quick-progress="${esc(x[1])}" data-quick-status="${x[2]}">${x[0]}</button>`).join('')}</div><textarea id="commentText" placeholder="输入进度，例如：已出图，等客户确认 / 已完成报价 / 今日暂停，原因是...；也可以直接 Ctrl+V / ⌘V 粘贴截图"></textarea><div class="quickProgress" style="margin:8px 0 0">${[0,25,50,75,100].map(v=>`<button type="button" data-progress-preset="${v}">${v}%</button>`).join('')}</div><div class="progressLine" style="margin-top:8px"><input id="commentProgressRange" type="range" min="0" max="100" step="1" value="${p}"><input id="commentProgress" type="number" min="0" max="100" step="1" value="${p}"></div><div style="margin-top:8px;display:flex;gap:6px;justify-content:flex-end"><button class="btn" type="button" onclick="saveProgressOnly()">保存进度百分比</button><button class="btn green" type="button" onclick="addComment()">保存进度记录</button></div></section>`}
function attachmentHtml(atts){return `<section class="detailSection"><div class="attachUploadBar"><div class="attachDrop"><div><strong>附件</strong><span>最大100MB，7天后自动删除</span></div><input id="attFile" type="file"><button class="btn mini" type="button" data-choose-attachment>上传</button></div></div><div class="attachGrid">${atts.map(attachmentCard).join('')||'<div class="empty">暂无附件</div>'}</div></section>`}
function attachmentCard(a){return `<article class="attachCard"><b>${esc(a.file_name)}</b><span>${fileSize(a.file_size)} · ${esc(a.user_name||'')}</span><span>${esc(a.created_at||'')} · ${Number(a.is_valid)?'有效至 '+esc(a.expires_at||''):'附件无效'}</span><div class="miniActions"><a class="btn" href="${API}?action=download_attachment&attachment_id=${a.id}" target="_blank">下载</a><button class="btn red" onclick="deleteAttachment(${a.id})">删除</button></div></article>`}
function stepsHtml(steps){return `<section class="detailSection"><h4>执行步骤 / 轻量流程</h4><div class="stepsList" id="stepsList">${steps.map(stepRow).join('')||'<div class="empty">暂无执行步骤</div>'}</div><button class="btn mini" type="button" onclick="addStepRow()" style="margin-top:8px">新增步骤</button></section>`}
function stepRow(s={}){return `<div class="stepRow" draggable="true" data-step-id="${esc(s.id||'')}"><span class="row-drag">⋮⋮</span><input data-step-field="step_name" value="${esc(s.step_name||'')}" placeholder="步骤名称"><select data-step-field="owner_id"><option value="">负责人</option>${userOptions(s.owner_id||'')}</select><select data-step-field="status">${['pending','in_progress','blocked','done','cancelled'].map(v=>`<option value="${v}" ${v===(s.status||'pending')?'selected':''}>${stepStatus(v)}</option>`).join('')}</select><button class="btn mini" onclick="saveStep(this)">保存</button><input type="datetime-local" data-step-field="due_at" value="${esc((s.due_at||'').replace(' ','T').slice(0,16))}"><input data-step-field="note" value="${esc(s.note||'')}" placeholder="备注"><button class="btn mini" onclick="stepDone(this)">完成</button><button class="btn mini" onclick="dispatchStep(this)">${s.child_task_id?'已派工':'派工'}</button><button class="btn mini red" onclick="deleteStep(this)">删除</button></div>`}
function timelineHtml(comments){return `<section class="detailSection"><h4>进度记录时间线</h4><div class="timeline">${comments.map(c=>`<article class="timelineItem"><header><b>${esc(c.user_name||'')}</b><em>${esc(c.created_at||'')}</em></header><p>${esc(c.comment||'')}</p>${c.progress!==null?`<span class="dtag blue">进度 ${esc(c.progress)}%</span>`:''}<div class="miniActions"><button class="btn" onclick="deleteComment(${c.id})">删除</button></div></article>`).join('')||'<div class="empty">暂无进度记录</div>'}</div></section>`}
function logsHtml(logs){return `<section class="detailSection"><h4>操作日志</h4><div class="logFilters">${['all','update','comment','upload','status','delete'].map(k=>`<button type="button" data-log-filter="${k}">${logFilterName(k)}</button>`).join('')}</div><div class="detailLog" id="detailLog" data-logs="${esc(JSON.stringify(logs||[]))}"></div></section>`}
function groupHtml(d){if(!d.group)return '';return `<section class="detailSection"><h4>多人组</h4><div class="detailSummary"><article><span>组标题</span><strong>${esc(d.group.title||'')}</strong></article><article><span>总人数</span><strong>${esc(d.group.total_count||0)}</strong></article><article><span>已完成</span><strong>${esc(d.group.done_count||0)}</strong></article></div><div class="stepsList" style="margin-top:8px">${(d.group_children||[]).map(c=>`<div class="notice"><b>${esc(c.assignee_name)}</b> · ${statusText(c.status)} · ${esc(c.progress)}% · 截止 ${esc(formatDue(c.due_at))} <button class="btn mini" onclick="openDetail(${c.id})">打开</button></div>`).join('')}</div></section>`}
function linkedHtml(t){if(!t.linked_system)return '';return `<section class="detailSection"><h4>CRM / PLM 联动信息</h4><div class="linkedCard"><article><span>来源系统</span><strong>${esc(t.linked_system)}</strong></article><article><span>关联标题</span><strong>${esc(t.linked_title||'')}</strong></article><article><span>关联 ID</span><strong>${esc(t.linked_id||'')}</strong></article><article><button class="btn mini" type="button">跳转 / 预览</button></article></div></section>`}
function detailFooter(t){let s=String(t.status||''),mine=Number(t.assigned_to||0)===Number(state.me?.id||0),creator=Number(t.created_by||0)===Number(state.me?.id||0)||t.can_urge,left=`<button class="btn" onclick="urgeFromDetail()">催办</button><button class="btn" onclick="saveDetail()">保存基础信息</button>`,center=[],right=[];if(s==='done'){center.push(`<button class="btn primaryAction" disabled>已完成</button>`);if(creator)center.push(`<button class="btn" onclick="detailStatus('start_task')">取消完成</button>`)}else{if(['accepted','in_progress','paused'].includes(s))center.push(`<button class="btn" onclick="detailStatus('pause_task')">暂停</button>`);if(['pending_accept','accepted','in_progress','paused','submitted'].includes(s))center.push(`<button class="btn primaryAction" onclick="detailStatus('complete_task')">完成</button>`);if(['accepted','in_progress','paused'].includes(s))center.push(`<button class="btn dangerAction" onclick="detailStatus('cancel_task')">取消</button>`)}if(s==='pending_accept')right.push(`<button class="btn primaryAction" onclick="detailStatus('accept_task')">接收任务</button>`);else if(s==='in_progress'&&mine)right.push(`<button class="btn primaryAction" onclick="detailStatus('submit_task')">提交确认</button>`);else if(s==='submitted'&&creator){right.push(`<button class="btn primaryAction" onclick="detailStatus('confirm_task_done')">确认完成</button>`);right.push(`<button class="btn" onclick="detailStatus('return_task')">退回</button>`)}return `<div class="detailFootActions"><div class="detailFootLeft">${left}</div><div class="detailFootCenter">${center.join('')}</div><div class="detailFootRight">${right.join('')}</div></div>`}
function bindDetailEvents(){let body=$('#detailBody');body.querySelectorAll('[data-detail-tab]').forEach(b=>b.onclick=()=>setDetailTab(b.dataset.detailTab,true));body.querySelectorAll('[data-detail-field]').forEach(el=>{let ev=el.tagName==='SELECT'||el.type==='date'||el.type==='datetime-local'||el.type==='number'?'change':'input';el.addEventListener(ev,()=>{setDetailSaveStatus(el.dataset.detailField,'pending');debounceDetailSave(el.dataset.detailField,el.value)})});let pr=body.querySelector('[data-detail-progress]'),pn=body.querySelector('[data-detail-field="progress"]');if(pr&&pn){pr.oninput=()=>{pn.value=progressClamp(pr.value);setDetailSaveStatus('progress','pending');debounceDetailSave('progress',pn.value)};pn.oninput=()=>{pn.value=progressClamp(pn.value);pr.value=pn.value;setDetailSaveStatus('progress','pending');debounceDetailSave('progress',pn.value)}}let cr=$('#commentProgressRange'),cn=$('#commentProgress');if(cr&&cn){cr.oninput=()=>{cn.value=progressClamp(cr.value)};cn.oninput=()=>{cn.value=progressClamp(cn.value);cr.value=cn.value};body.querySelectorAll('[data-progress-preset]').forEach(b=>b.onclick=()=>{let v=progressClamp(b.dataset.progressPreset);cr.value=v;cn.value=v})}$('#commentText')?.addEventListener('keydown',e=>{if(e.ctrlKey&&e.key==='Enter'){e.preventDefault();addComment()}});body.querySelectorAll('[data-quick-progress]').forEach(b=>b.onclick=()=>quickProgress(b.dataset.quickProgress,b.dataset.quickStatus));body.querySelectorAll('[data-log-filter]').forEach(b=>b.onclick=()=>renderDetailLogs(b.dataset.logFilter));bindImageUploadEvents();bindAttachmentUploadEvents()}
function progressClamp(v){let n=Number(v);if(!Number.isFinite(n))n=0;return Math.max(0,Math.min(100,Math.round(n)))}
function bindImageUploadEvents(){let body=$('#detailBody'),input=body?.querySelector('#imgFile');if(input)input.onchange=()=>{let f=imageFileFromList(input.files);if(f)uploadImage(f);else setImageUploadStatus('请选择图片文件','error')};body?.querySelector('[data-choose-image]')?.addEventListener('click',e=>{e.preventDefault();e.stopPropagation();chooseImage()});let drop=$('#imgDrop');if(drop){drop.ondragover=e=>{e.preventDefault();e.stopPropagation();drop.classList.add('dragging')};drop.ondragleave=()=>drop.classList.remove('dragging');drop.ondrop=e=>{e.preventDefault();e.stopPropagation();drop.classList.remove('dragging');let f=imageFileFromList(e.dataTransfer.files);if(f)uploadImage(f);else setImageUploadStatus('请拖入图片文件','error')}}let modal=$('#detailModal');if(modal)modal.onpaste=pasteImage}
function bindAttachmentUploadEvents(){let body=$('#detailBody');body?.querySelector('[data-choose-attachment]')?.addEventListener('click',e=>{e.preventDefault();e.stopPropagation();$('#attFile')?.click()})}
function setDetailTab(tab,resetScroll=true){let body=$('#detailBody');if(!body)return;let panes=$all('[data-detail-pane]',body),keys=panes.map(p=>p.dataset.detailPane);if(!keys.includes(tab))tab='detail';state.detailTab=tab;$all('[data-detail-tab]',body).forEach(b=>b.classList.toggle('active',b.dataset.detailTab===tab));panes.forEach(p=>p.classList.toggle('active',p.dataset.detailPane===tab));if(resetScroll)body.scrollTop=0;loadDetailTabData(tab)}
function detailTaskId(){return Number(state.currentDetail?.task?.id||0)}
function detailPane(tab){return document.querySelector(`[data-detail-pane="${tab}"]`)}
function detailPaneError(tab,e){let pane=detailPane(tab);if(pane)pane.innerHTML=`<section class="detailSection"><div class="empty">加载失败：${esc(e.message||e||'未知错误')}</div></section>`}
async function loadDetailTabData(tab){let id=detailTaskId();if(!id||tab==='detail')return;let key='detail_tab_'+tab+'_'+id;clearTimeout(state.saveTimers[key]);state.saveTimers[key]=setTimeout(async()=>{try{let pane=detailPane(tab);if(!pane)return;if(tab==='progress'){let comments=await api('list_comments',{task_id:id});pane.innerHTML=progressHtml(state.currentDetail.task)+timelineHtml(comments||[]);bindDetailEvents();return}if(tab==='images'){let imgs=await api('list_images',{task_id:id});pane.innerHTML=imageUploadHtml(imgs||[]);bindImageUploadEvents();return}if(tab==='attachments'){let atts=await api('list_attachments',{task_id:id});pane.innerHTML=attachmentHtml(atts||[]);bindAttachmentUploadEvents();return}if(tab==='steps'){let steps=await api('list_steps',{task_id:id});pane.innerHTML=stepsHtml(steps||[]);return}if(tab==='logs'){let logs=await api('list_task_logs',{task_id:id});pane.innerHTML=logsHtml(logs||[]);bindDetailEvents();renderDetailLogs('all');return}}catch(e){detailPaneError(tab,e)}},80)}
function setDetailSaveStatus(field,status,msg=''){if(!field)return;if(status)state.detailSaveStatus[field]={status,msg,ts:Date.now()};else delete state.detailSaveStatus[field];$all(`[data-detail-field="${field}"]`).forEach(el=>applyCellSaveStatusToElement(el,status));if(status==='saved')setTimeout(()=>{let rec=state.detailSaveStatus[field];if(rec&&rec.status==='saved'&&Date.now()-rec.ts>=1000){delete state.detailSaveStatus[field];$all(`[data-detail-field="${field}"]`).forEach(el=>applyCellSaveStatusToElement(el,''))}},1200)}
function restoreDetailSaveStatuses(){Object.entries(state.detailSaveStatus||{}).forEach(([field,rec])=>$all(`[data-detail-field="${field}"]`).forEach(el=>applyCellSaveStatusToElement(el,rec.status)))}
function debounceDetailSave(field,value){clearTimeout(state.saveTimers['detail_'+field]);state.saveTimers['detail_'+field]=setTimeout(()=>saveDetailField(field,value),500)}
async function saveDetailField(field,value){let t=state.currentDetail?.task;if(!t)return;try{setDetailSaveStatus(field,'saving');let r=await api('update_cell',{task_id:t.id,field,value,client_updated_at:t.updated_at||''});updateTaskVersion(t.id,r.updated_at);setDetailSaveStatus(field,'saved');$('#syncState').textContent='详情已同步 '+new Date().toLocaleTimeString('zh-CN',{hour12:false})}catch(e){let msg=String(e.message||'保存失败');setDetailSaveStatus(field,'error',msg);toast(msg);$('#syncState').textContent=msg.includes('已被别人更新')?'详情保存冲突，当前输入已保留':'详情保存失败'}}
async function saveDetail(){let t=state.currentDetail.task;let data={id:t.id,client_updated_at:t.updated_at||''};$all('[data-detail-field]').forEach(el=>data[el.dataset.detailField]=el.value);try{let r=await api('update_task',data);updateTaskVersion(t.id,r.updated_at);state.detailSaveStatus={};toast('基础信息已保存');await refreshDetail(true)}catch(e){let msg=String(e.message||'保存基础信息失败');toast(msg);$('#syncState').textContent=msg}}
function captureDetailView(){let body=$('#detailBody');return {tab:state.detailTab||'detail',scrollTop:body?body.scrollTop:0}}
function restoreDetailView(v){if(!v)return;state.detailTab=v.tab||state.detailTab||'detail';setDetailTab(state.detailTab,false);requestAnimationFrame(()=>{let body=$('#detailBody');if(body)body.scrollTop=v.scrollTop||0})}
async function refreshDetail(silent=false){let id=state.currentDetail?.task?.id||state.currentDetail?.members?.[0]?.task_id;if(!id)return;if(state.currentDetail?.group&&Array.isArray(state.currentDetail?.members)&&!state.memberDetailMode){let d=await api('multi_group_detail',{id});state.currentDetail=d;renderMultiDetail(d);if(!silent)toast('详情已刷新');return}let view=captureDetailView(),d=await api(state.memberDetailMode?'multi_member_detail':'task_detail',{id});if(isMultiDetail(d)&&!state.memberDetailMode){d=await api('multi_group_detail',{id});state.currentDetail=d;renderMultiDetail(d);if(!silent)toast('详情已刷新');return}state.currentDetail=d;renderDetail(d);restoreDetailView(view);if(!silent)toast('详情已刷新')}
function closeDetail(){detailModal.close();load({silent:true})}
function copyDetailLink(){let id=state.currentDetail?.task?.id||'';let url=location.origin+location.pathname+'?task_id='+id;navigator.clipboard?.writeText(url);toast('任务链接已复制')}
async function addComment(){let t=state.currentDetail.task,txt=$('#commentText').value.trim();if(!txt)return toast('请输入进度记录');await api('add_comment',{task_id:t.id,comment:txt,progress:$('#commentProgress').value});toast('进度已保存');await refreshDetail(true)}
async function saveProgressOnly(){let t=state.currentDetail.task;await api('save_progress',{task_id:t.id,progress:$('#commentProgress').value});toast('进度百分比已保存');await refreshDetail(true)}
async function quickProgress(text,status){let box=$('#commentText');box.value=(box.value?box.value+'\n':'')+text;if(status==='done'){await api('complete_task',{id:state.currentDetail.task.id});await api('add_comment',{task_id:state.currentDetail.task.id,comment:text,progress:100});toast('已完成并记录进度');await refreshDetail(true)}else if(status==='paused'){await api('pause_task',{id:state.currentDetail.task.id});toast('已写入暂停提示')}else if(status==='in_progress'){await api('start_task',{id:state.currentDetail.task.id}).catch(()=>{});toast('已写入进度提示')}}
async function detailStatus(action){await api(action,{id:state.currentDetail.task.id});toast('状态已更新');await refreshDetail(true)}
async function urgeFromDetail(){let note=prompt('催办说明','请尽快处理这条派工');if(note===null)return;await api('urge_task',{id:state.currentDetail.task.id,note});toast('已催办');await refreshDetail(true)}
function chooseImage(){let input=document.querySelector('[data-detail-pane="images"] #imgFile')||$('#imgFile');if(!input)return setImageUploadStatus('图片上传入口未找到','error');input.click()}
function setImageUploadStatus(msg,type=''){let box=$('#imageUploadStatus');if(box){box.textContent=msg||'';box.classList.toggle('error',type==='error')}if(msg)toast(msg)}
function imageFileFromList(list){return [...(list||[])].find(f=>f&&String(f.type||'').startsWith('image/'))||null}
function canvasBlob(canvas,type,quality){return new Promise(resolve=>canvas.toBlob(resolve,type,quality))}
function loadImageFile(file){return new Promise((resolve,reject)=>{let url=URL.createObjectURL(file),img=new Image();img.onload=()=>{URL.revokeObjectURL(url);resolve(img)};img.onerror=()=>{URL.revokeObjectURL(url);reject(new Error('图片读取失败'))};img.src=url})}
async function prepareImageUpload(file){if(!file||!String(file.type||'').startsWith('image/'))throw new Error('请选择图片文件');if(file.size<=500*1024)return file;let img=await loadImageFile(file),max=1600,scale=Math.min(1,max/Math.max(img.width,img.height)),w=Math.max(1,Math.round(img.width*scale)),h=Math.max(1,Math.round(img.height*scale)),canvas=document.createElement('canvas');canvas.width=w;canvas.height=h;let ctx=canvas.getContext('2d');ctx.fillStyle='#fff';ctx.fillRect(0,0,w,h);ctx.drawImage(img,0,0,w,h);for(let q of [.86,.78,.7,.62,.54,.46,.38,.3]){let b=await canvasBlob(canvas,'image/jpeg',q);if(b&&b.size<=500*1024)return new File([b],(file.name||'image').replace(/\.[^.]+$/, '')+'.jpg',{type:'image/jpeg'})}let b=await canvasBlob(canvas,'image/jpeg',.24);if(!b)throw new Error('图片压缩失败');return new File([b],(file.name||'image').replace(/\.[^.]+$/, '')+'.jpg',{type:'image/jpeg'})}
async function refreshDetailImages(){let id=state.currentDetail?.task?.id,pane=document.querySelector('[data-detail-pane="images"]');if(!id||!pane)return refreshDetail(true);let imgs=await api('list_images',{task_id:id});pane.innerHTML=imageUploadHtml(imgs||[]);bindImageUploadEvents()}
async function uploadImage(file){if(!state.currentDetail)return setImageUploadStatus('请先打开任务详情','error');if(!file)return;try{setImageUploadStatus('图片处理中...');$('#syncState').textContent='图片处理中';let ready=await prepareImageUpload(file);setImageUploadStatus('图片上传中...');$('#syncState').textContent='图片上传中';await api('upload_image',{task_id:state.currentDetail.task.id},ready);let input=$('#imgFile');if(input)input.value='';setImageUploadStatus('图片已上传');$('#syncState').textContent='图片已上传';await refreshDetailImages()}catch(e){let msg=e.message||'图片上传失败';setImageUploadStatus(msg,'error');$('#syncState').textContent=msg}}
async function refreshDetailAttachments(){let id=state.currentDetail?.task?.id,pane=document.querySelector('[data-detail-pane="attachments"]');if(!id||!pane)return refreshDetail(true);let atts=await api('list_attachments',{task_id:id});pane.innerHTML=attachmentHtml(atts||[]);bindAttachmentUploadEvents()}
async function uploadAttachment(){let f=$('#attFile')?.files?.[0];if(!f)return toast('请选择附件');$('#syncState').textContent='附件上传中';await api('upload_attachment',{task_id:state.currentDetail.task.id},f);let input=$('#attFile');if(input)input.value='';toast('附件已上传');$('#syncState').textContent='附件已上传';await refreshDetailAttachments()}
async function deleteAttachment(id){if(!confirm('确认删除附件？'))return;await api('delete_attachment',{attachment_id:id});toast('附件已删除');if(state.detailTab==='images')return refreshDetailImages();if(state.detailTab==='attachments')return refreshDetailAttachments();await refreshDetail(true)}
async function deleteComment(id){if(!confirm('确认删除这条进度记录？'))return;await api('delete_comment',{comment_id:id});toast('进度已删除');await refreshDetail(true)}
function pasteImage(e){if(!state.currentDetail||!$('#detailModal')?.open)return;for(const item of e.clipboardData?.items||[])if(item.type.startsWith('image/')){uploadImage(item.getAsFile());e.preventDefault();break}}
function previewImage(src){let dlg=$('#imagePreview');$('#imagePreviewImg').src=src;if(dlg.open)dlg.close();dlg.onclick=e=>{if(e.target===dlg)dlg.close()};try{dlg.showModal()}catch(e){dlg.show()}}
function fileSize(v){let n=Number(v||0);if(n>1024*1024)return (n/1024/1024).toFixed(1)+'MB';if(n>1024)return Math.ceil(n/1024)+'KB';return n+'B'}
function stepStatus(s){return {pending:'未开始',in_progress:'进行中',blocked:'卡住',done:'已完成',cancelled:'取消'}[s]||s}
function addStepRow(){let box=$('#stepsList');box?.querySelector('.empty')?.remove();box?.insertAdjacentHTML('beforeend',stepRow({sort_order:Date.now()}))}
function stepPayload(btn){let row=btn.closest('.stepRow'),data={task_id:state.currentDetail.task.id,step_id:row.dataset.stepId||0};row.querySelectorAll('[data-step-field]').forEach(el=>data[el.dataset.stepField]=el.value);data.sort_order=[...row.parentNode.children].indexOf(row)*10+10;return data}
async function saveStep(btn){await api('save_step',stepPayload(btn));toast('步骤已保存');await refreshDetail(true)}
async function deleteStep(btn){let row=btn.closest('.stepRow'),id=row.dataset.stepId;if(!id){row.remove();return}if(!confirm('删除步骤？'))return;await api('delete_step',{step_id:id});toast('步骤已删除');await refreshDetail(true)}
async function stepDone(btn){let id=btn.closest('.stepRow').dataset.stepId;if(!id)return saveStep(btn);await api('complete_step',{step_id:id});toast('步骤已完成');await refreshDetail(true)}
async function dispatchStep(btn){let row=btn.closest('.stepRow'),id=row.dataset.stepId;if(!id){await saveStep(btn);return toast('请再次点击派工')}let r=await api('dispatch_step',{step_id:id});toast('已生成子派工 #'+r.child_task_id);await refreshDetail(true)}
function logFilterName(k){return {all:'全部',update:'修改',comment:'进度',upload:'附件',status:'状态',delete:'删除/恢复'}[k]||k}
function renderDetailLogs(filter='all'){let box=$('#detailLog');if(!box)return;let logs=[];try{logs=JSON.parse(box.dataset.logs||'[]')}catch(e){};$all('[data-log-filter]').forEach(b=>b.classList.toggle('active',b.dataset.logFilter===filter));let rows=logs.filter(l=>filter==='all'||String(l.action_type||'').includes(filter)||String(l.note||'').includes(logFilterName(filter))).slice(0,20);box.innerHTML=rows.map(detailLogHtml).join('')||'<div class="empty">暂无日志</div>'}
function detailLogHtml(l){let note=String(l.note||'').trim(),fallback=(l.old_value||l.new_value)?`<div style="white-space:pre-wrap">从：${esc(l.old_value||'空')}\n改为：${esc(l.new_value||'空')}</div>`:'';return `<div class="log"><b>${esc(l.user_name||'')}</b> ${esc(l.action_type||'操作')}${l.field_name?' · '+esc(logFieldLabel(l.field_name)):''}<br><em>${esc(l.created_at||'')}</em>${note?`<div style="white-space:pre-wrap">${esc(note)}</div>`:fallback}</div>`}
function logFieldLabel(field){return {title:'任务标题',project:'项目 / 任务内容',description:'详细说明',priority:'优先级',status:'状态',assigned_to:'负责人',due_at:'截止日期',task_date:'任务日期',progress:'进度',dispatch_mode:'方式',is_deleted:'删除状态',remind_count:'催办次数',step:'执行步骤',step_status:'步骤状态',child_task_id:'子派工'}[field]||String(field||'').replace(/^custom_/,'自定义列 ')}
document.addEventListener('change',e=>{if(e.target.id==='attFile'&&e.target.files[0])uploadAttachment()});document.addEventListener('dragover',e=>{if(e.target.closest('#imgDrop')){e.preventDefault();e.stopPropagation()}});document.addEventListener('drop',e=>{if(e.target.closest('#imgDrop')){e.preventDefault();e.stopPropagation();let f=imageFileFromList(e.dataTransfer.files);if(f)uploadImage(f);else setImageUploadStatus('请拖入图片文件','error')}})
async function doUrge(id){await api('urge_task',{id});toast('已催办');load()}async function doDelete(id,gid){if(gid){if(!confirm('删除整组多人？'))return;await api('delete_multi',{group_id:gid})}else{if(!confirm('确认删除？'))return;await api('delete_task',{id})}toast('已删除');load()}async function quickDone(id,currentStatus){if(String(id).startsWith('g'))return;let next=currentStatus==='done'?'in_progress':'done';let payload=next==='done'?{id,status:'done',progress:100,client_updated_at:taskVersion(id)}:{id,status:'in_progress',client_updated_at:taskVersion(id)};try{let r=await api('update_task',payload);updateTaskVersion(id,r.updated_at);toast(next==='done'?'已完成':'已恢复进行中');load()}catch(e){toast(e.message);if(String(e.message||'').includes('已被别人更新'))load({silent:true})}}
function openSimple(title,html){$('#formTitle').textContent=title;$('#formHint').textContent='当天同账号只显示一次。';$('#formBody').innerHTML=html;$('#formSave').style.display='none';$('#formModal').showModal()}
init().catch(e=>toast(e.message));
</script>
</body>
</html>
